// This file handles the obfuscation and dynamic loading of the Google Maps API.

// The encrypted blob (Byte Array)
// This represents "AIzaSyBCWH72da5n-rq8Qu3sOc64cW_asGZpy0w"
// XOR-ed with password "Serverless Odometer Planning"
const ENCRYPTED_KEY_BLOB = [
    18, 44, 10, 23, 54, 7, 42, 34, 36, 43, 23, 125, 0, 14, 88, 11, 73, 19, 31, 24, 1, 25, 82, 29, 33, 10, 72, 87, 48, 50, 45, 23, 14, 53, 54, 13, 10, 67, 87
];

// Simple XOR Cipher
const xorCipher = (input: number[], password: string): string => {
    let result = '';
    for (let i = 0; i < input.length; i++) {
        const passChar = password.charCodeAt(i % password.length);
        const decryptedChar = String.fromCharCode(input[i] ^ passChar);
        result += decryptedChar;
    }
    return result;
};

export const SecurityService = {
    /**
     * Attempts to decrypt the API key using the provided password.
     * Returns the key if it looks valid (Starts with 'AIza'), otherwise null.
     */
    decryptKey: (password: string): string | null => {
        if (!password) return null;
        try {
            const decrypted = xorCipher(ENCRYPTED_KEY_BLOB, password);
            // Basic format check for Google API Keys
            if (decrypted.startsWith('AIza')) {
                return decrypted;
            }
            return null;
        } catch (e) {
            return null;
        }
    },

    /**
     * Dynamically injects the Google Maps script into the DOM.
     * Prevents duplicate injection.
     */
    loadGoogleMapsScript: (apiKey: string): Promise<void> => {
        return new Promise((resolve, reject) => {
            // Check if already loaded
            if ((window as any).google && (window as any).google.maps) {
                resolve();
                return;
            }

            // Check if script tag already exists (e.g. loading)
            const existingScript = document.getElementById('google-maps-script');
            if (existingScript) {
                // If it exists but google isn't ready, we might need to wait or it might be broken.
                // For simplicity, we assume if the tag is there, it's handling it.
                // But a proper loader might check status.
                // Here we just resolve to let the app try to use it.
                resolve(); 
                return;
            }

            const script = document.createElement('script');
            script.id = 'google-maps-script';
            script.src = `https://maps.googleapis.com/maps/api/js?key=${apiKey}&libraries=places`;
            script.async = true;
            script.defer = true;

            script.onload = () => {
                resolve();
            };

            script.onerror = (e) => {
                reject(new Error("Failed to load Google Maps script. Check connection or Key."));
            };

            document.head.appendChild(script);
        });
    }
};

import { DistanceCache } from './distanceCache';

// Access global google object
declare const google: any;

// Mutable state for the API Key (set at runtime via Security Gate)
let runtimeApiKey: string | null = null;

export const setRuntimeApiKey = (key: string) => {
    runtimeApiKey = key;
};

// Helper for console logging
const logApiCall = (method: string, duration: number, details?: string) => {
    console.debug(`%c[OdoCalc API] ${method} took ${duration.toFixed(2)}ms ${details ? `(${details})` : ''}`, 'color: #1a73e8; font-weight: bold;');
};

// Standard Route Data - checks LMOD Cache first
export const getRouteData = async (origin: string, dest: string): Promise<{ distanceKm: number, durationSeconds: number }> => {

  // 1. Check LMOD Cache
  const cached = DistanceCache.get(origin, dest);
  if (cached) {
      // console.debug(`[LMOD] Cache hit: ${origin} -> ${dest}`); // Optional: Log cache hits?
      return Promise.resolve(cached);
  }

  // 2. Fetch from API if missing
  return new Promise((resolve, reject) => {
    if (!(window as any).google || !(window as any).google.maps) {
      reject("Google Maps SDK not loaded. Please enter API Password in Settings.");
      return;
    }

    const start = performance.now();
    const service = new google.maps.DistanceMatrixService();
    service.getDistanceMatrix(
      {
        origins: [origin],
        destinations: [dest],
        travelMode: 'DRIVING',
        unitSystem: google.maps.UnitSystem.METRIC,
      },
      (response: any, status: string) => {
        const end = performance.now();
        logApiCall('DistanceMatrix (Single)', end - start);

        if (status !== 'OK') return reject(`Matrix API Error: ${status}`);

        const element = response.rows[0].elements[0];
        if (element.status !== 'OK') {
          if (element.status === 'ZERO_RESULTS') return reject(`No driving route found to: ${dest}`);
          return reject(`Route error for ${dest}: ${element.status}`);
        }

        const result = {
            distanceKm: element.distance.value / 1000.0,
            durationSeconds: element.duration.value
        };

        // 3. Save to LMOD Cache
        DistanceCache.set(origin, dest, result);

        resolve(result);
      }
    );
  });
};

// Batch Fetch for Matrix Optimization
// This ensures we have data for all pairs before running TSP
export const ensureMatrixData = async (addresses: string[], onProgress?: (msg: string) => void): Promise<void> => {
    if (!(window as any).google || !(window as any).google.maps) {
        throw new Error("Google Maps SDK not loaded. Check Password.");
    }

    // 1. Identify missing pairs
    // We need a full N x N matrix ideally, or at least Start->All, All->Start, and Inter-Visit pairs
    // For simplicity and robustness of 2-Opt, we fetch the full square matrix of unique addresses.
    const uniqueAddresses = Array.from(new Set(addresses.map(a => a.trim())));

    // Google Matrix API works best when we send a set of Origins and Destinations.
    // Limits: 25 origins max, 25 dests max, 100 elements total per call.
    // e.g. 10 origins x 10 dests = 100 elements.

    // We will naively iterate pairs to see if we have high cache coverage, 
    // but the most efficient way to fill the cache for TSP is to batch calls.

    // Let's break uniqueAddresses into chunks of 10 (since 10x10=100 elements max)
    const chunkSize = 10;
    const service = new google.maps.DistanceMatrixService();

    for (let i = 0; i < uniqueAddresses.length; i += chunkSize) {
        for (let j = 0; j < uniqueAddresses.length; j += chunkSize) {

            const originsChunk = uniqueAddresses.slice(i, i + chunkSize);
            const destsChunk = uniqueAddresses.slice(j, j + chunkSize);

            // Check if we need to fetch this chunk
            // If we have ALL data in this sub-grid, skip it.
            let needsFetch = false;
            for (const o of originsChunk) {
                for (const d of destsChunk) {
                    if (o === d) continue;
                    if (!DistanceCache.has(o, d)) {
                        needsFetch = true;
                        break;
                    }
                }
                if (needsFetch) break;
            }

            if (!needsFetch) {
                continue;
            }

            if (onProgress) onProgress(`Fetching distance data... (${i + 1}-${Math.min(i+chunkSize, uniqueAddresses.length)} vs ${j + 1}-${Math.min(j+chunkSize, uniqueAddresses.length)})`);

            // Fetch Chunk
            const start = performance.now();
            await new Promise<void>((resolve, reject) => {
                service.getDistanceMatrix(
                    {
                        origins: originsChunk,
                        destinations: destsChunk,
                        travelMode: 'DRIVING',
                        unitSystem: google.maps.UnitSystem.METRIC,
                    },
                    (response: any, status: string) => {
                        const end = performance.now();
                        logApiCall('DistanceMatrix (Batch)', end - start, `${originsChunk.length}x${destsChunk.length}`);

                        if (status !== 'OK') {
                            console.error(`Matrix API Error: ${status}`);
                            // We don't reject here to allow partial success, but TSP might be suboptimal
                            resolve(); 
                            return;
                        }

                        // Process response
                        response.rows.forEach((row: any, rIdx: number) => {
                            const origin = originsChunk[rIdx];
                            row.elements.forEach((element: any, cIdx: number) => {
                                const dest = destsChunk[cIdx];
                                if (element.status === 'OK') {
                                    DistanceCache.set(origin, dest, {
                                        distanceKm: element.distance.value / 1000.0,
                                        durationSeconds: element.duration.value
                                    });
                                }
                            });
                        });
                        resolve();
                    }
                );
            });

            // Brief delay to be nice to the API rate limiter
            await new Promise(r => setTimeout(r, 500));
        }
    }
};


export const validateAddressStrict = async (addressStr: string): Promise<string> => {
  if (!runtimeApiKey) {
      throw new Error("Security Lock: API Key not loaded. Enter password in Settings.");
  }

  const url = `https://addressvalidation.googleapis.com/v1:validateAddress?key=${runtimeApiKey}`;
  const payload = {
    address: { regionCode: "CZ", addressLines: [addressStr] },
    enableUspsCass: false,
  };

  try {
    const start = performance.now();
    const resp = await fetch(url, {
      method: 'POST',
      body: JSON.stringify(payload),
    });
    const data = await resp.json();
    const end = performance.now();
    logApiCall('AddressValidation (REST)', end - start);

    if (data.error) throw new Error("Validation API: " + data.error.message);

    const verdict = data.result?.verdict || {};
    const addrObj = data.result?.address || {};

    // Specific logic requested by user in original code
    if (verdict.hasUnconfirmedComponents) throw new Error(`Unconfirmed address components: ${addressStr}`);
    if (verdict.validationGranularity === 'OTHER') throw new Error(`Address too vague (City level): ${addressStr}`);

    return addrObj.formattedAddress || addressStr;
  } catch (err) {
    throw err;
  }
};

// UI Helper for instant validation
export interface ValidationResult {
    isValid: boolean;
    formattedAddress?: string;
    error?: string;
}

export const checkAddress = async (addressStr: string): Promise<ValidationResult> => {
    if (!addressStr || addressStr.trim().length < 3) {
        return { isValid: false, error: 'Address too short' };
    }
    // Early exit if key not loaded
    if (!runtimeApiKey && !(window as any).google) {
        return { isValid: false, error: 'Locked: Password required' };
    }

    try {
        const formatted = await validateAddressStrict(addressStr);
        return { isValid: true, formattedAddress: formatted };
    } catch (e: any) {
        return { isValid: false, error: e.message || 'Invalid address' };
    }
}

import React, { useState, useEffect } from 'react';
import { AppSettings } from '../types';
import { checkAddress } from '../services/googleMapsService';
import { SecurityService } from '../services/security';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  settings: AppSettings;
  onSave: (newSettings: AppSettings) => void;
}

export const SettingsModal: React.FC<SettingsModalProps> = ({ isOpen, onClose, settings, onSave }) => {
  const [formData, setFormData] = useState<AppSettings>(settings);
  const [validationStatus, setValidationStatus] = useState<{isValid?: boolean, msg?: string}>({});
  const [isValidating, setIsValidating] = useState(false);
  const [passwordStatus, setPasswordStatus] = useState<'valid' | 'invalid' | 'unknown'>('unknown');

  useEffect(() => {
    if (isOpen) {
        setFormData(settings);
        if (settings.isStartValid) {
            setValidationStatus({ isValid: true, msg: 'Address validated' });
        } else {
            setValidationStatus({});
        }

        // Check current password status
        if (settings.apiPassword) {
            const key = SecurityService.decryptKey(settings.apiPassword);
            setPasswordStatus(key ? 'valid' : 'invalid');
        } else {
            setPasswordStatus('unknown');
        }
    }
  }, [isOpen, settings]);

  if (!isOpen) return null;

  const handleBlur = async () => {
      if (!formData.startAddress) return;

      setIsValidating(true);
      const result = await checkAddress(formData.startAddress);
      setIsValidating(false);

      if (result.isValid) {
          setValidationStatus({ isValid: true, msg: result.formattedAddress });
          // CHANGE: Do not overwrite startAddress with formatted version.
          setFormData(prev => ({ 
              ...prev, 
              isStartValid: true
          }));
      } else {
          setValidationStatus({ isValid: false, msg: result.error });
          setFormData(prev => ({ ...prev, isStartValid: false }));
      }
  };

  const handlePasswordChange = (val: string) => {
      setFormData(prev => ({ ...prev, apiPassword: val }));

      if (val.length > 5) {
          const key = SecurityService.decryptKey(val);
          setPasswordStatus(key ? 'valid' : 'invalid');
      } else {
          setPasswordStatus('unknown');
      }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave(formData);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow-xl w-full max-w-md p-6 animate-fade-in-up transition-colors">
        <h3 className="text-xl font-semibold mb-4 text-gray-800 dark:text-white">Application Settings</h3>

        <form onSubmit={handleSubmit} className="space-y-5">

          {/* Security Gate */}
          <div className="bg-blue-50 dark:bg-blue-900/20 p-3 rounded-md border border-blue-100 dark:border-blue-800">
             <label className="block text-sm font-bold text-gray-700 dark:text-gray-200 mb-1">
                 API Access Password <span className="text-red-500">*</span>
             </label>
             <div className="relative">
                 <input 
                   type="password" 
                   required
                   className={`w-full border rounded-md p-2 focus:ring-2 outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white
                      ${passwordStatus === 'valid' ? 'border-green-400 focus:ring-green-300' : ''}
                      ${passwordStatus === 'invalid' ? 'border-red-400 focus:ring-red-300' : 'border-gray-300 dark:border-gray-600 focus:ring-google-blue'}
                   `}
                   value={formData.apiPassword || ''}
                   onChange={e => handlePasswordChange(e.target.value)}
                   placeholder="Enter secret password"
                 />
                 <div className="absolute right-2 top-2.5">
                    {passwordStatus === 'valid' && (
                        <svg className="w-5 h-5 text-green-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
                    )}
                    {passwordStatus === 'invalid' && (
                        <svg className="w-5 h-5 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                    )}
                 </div>
             </div>
             <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">
                 Required to unlock map features.
             </p>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Start / End Address</label>
            <div className="relative">
                <textarea 
                rows={3}
                required
                className={`w-full border rounded-md p-2 focus:ring-2 outline-none resize-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white
                    ${validationStatus.isValid === false ? 'border-red-300 focus:ring-red-200' : 'border-gray-300 dark:border-gray-600 focus:ring-google-blue'}`}
                value={formData.startAddress}
                onChange={e => {
                    setFormData({...formData, startAddress: e.target.value, isStartValid: false});
                    setValidationStatus({}); 
                }}
                onBlur={handleBlur}
                placeholder="e.g. J. Palacha 324, Pardubice"
                />
                {isValidating && (
