      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (event) => {
          try {
              const text = event.target?.result as string;
              const data = JSON.parse(text);

              // Basic validation
              if (!data.visits && !data.settings) {
                  throw new Error("Invalid backup file format");
              }

              // Restore LMOD Cache directly to LocalStorage (bypassing React State)
              if (data.lmod) {
                  localStorage.setItem('odocalc_lmod', JSON.stringify(data.lmod));
              }

              // Restore App State
              if (data.settings) setSettings(data.settings);

              if (data.visits) {
                  setVisits(data.visits);
                  setStartTrip(data.start || null);
                  setReturnTrip(data.return || null);
              }

              // Handle Key Restore
              if (data.settings?.googleApiKey) {
                  setRuntimeApiKey(data.settings.googleApiKey);
                  loadGoogleMapsScript(data.settings.googleApiKey)
                    .then(() => setIsApiReady(true))
                    .catch(() => setIsApiReady(false));
              }

              alert("Import successful! Database updated.");

          } catch (err: any) {
              alert("Import failed: " + err.message);
          }
      };
      reader.readAsText(file);

      // Reset input
      if (importDbInputRef.current) importDbInputRef.current.value = '';
  };

  const handleClearDB = () => {
      if (dbDeleteConfirming) {
          // Clear LMOD Cache
          localStorage.removeItem('odocalc_lmod');

          // Reset State to Defaults
          setVisits([]);
          setStartTrip(null);
          setReturnTrip(null);
          setSettings({
            startAddress: "Dlouhá 1113, 530 06 Pardubice, Česko",
            currentOdometer: 0,
            departureTime: "08:00:00",
            isStrictMode: false,
            isStartValid: false,
            isDarkMode: true,
            googleApiKey: '', // Reset Key
            cacheExpirationDays: 30
          });

          setRuntimeApiKey("");
          setIsApiReady(false);
          setCacheExpirationDays(30); // Reset cache config

          setDbDeleteConfirming(false);
          alert("Database cleared (Factory Reset). API Key removed.");
      } else {
          setDbDeleteConfirming(true);
          setTimeout(() => setDbDeleteConfirming(false), 4000);
      }
  };

  // --- Actions ---

  const reindexVisits = (list: Visit[]) => {
    let orderCounter = 1;
    return list.map((v) => {
        // If skipped, set order to 0 (or keep internal track, but UI expects 0 to show empty)
        if (v.isSkipped) {
            return { ...v, order: 0 };
        }
        return { ...v, order: orderCounter++ };
    });
  };

  const handleReorder = (newVisits: Visit[]) => {
    // Reorder clears calculation
    const cleared = clearCalculation(newVisits);
    setVisits(reindexVisits(cleared));
  };

  const handleToggleSkip = (id: string) => {
      // Toggle skipped status
      const updated = visits.map(v => v.id === id ? { ...v, isSkipped: !v.isSkipped } : v);
      // Logic requires route recalculation because a stop is added/removed
      const cleared = clearCalculation(updated);
      setVisits(reindexVisits(cleared));
  };

  const handleAdd = () => {
    setEditingVisit(null);
    setIsModalOpen(true);
  };

  const handleEdit = (visit: Visit) => {
    setEditingVisit(visit);
    setIsModalOpen(true);
  };

  const saveVisit = (data: Omit<Visit, 'id'>) => {
    let newList;
    if (editingVisit) {
      // Update existing
      newList = visits.map(v => v.id === editingVisit.id ? { ...v, ...data } : v);
    } else {
      // Create new
      const newVisit = { ...data, id: uuid(), order: 0, isSkipped: false }; // Order will be set by reindex
      newList = [...visits, newVisit];
    }
    const cleared = clearCalculation(newList);
    setVisits(reindexVisits(cleared));
    setIsModalOpen(false);
  };

  const saveSettings = (newSettings: AppSettings) => {
      // If start address or odometer changed, invalidate results
      if (newSettings.startAddress !== settings.startAddress || newSettings.currentOdometer !== settings.currentOdometer || newSettings.departureTime !== settings.departureTime) {
          const cleared = clearCalculation(visits);
          setVisits(cleared);
      }

      // Check Key Change
      if (newSettings.googleApiKey !== settings.googleApiKey) {
          if (newSettings.googleApiKey) {
              setRuntimeApiKey(newSettings.googleApiKey);
              loadGoogleMapsScript(newSettings.googleApiKey)
                .then(() => setIsApiReady(true))
                .catch(e => {
                    console.error(e);
                    setIsApiReady(false);
                    alert("Failed to load Maps API with this key.");
                });
          } else {
              setRuntimeApiKey("");
              setIsApiReady(false);
          }
      }

      // Update Cache Config
      if (newSettings.cacheExpirationDays && newSettings.cacheExpirationDays !== settings.cacheExpirationDays) {
          setCacheExpirationDays(newSettings.cacheExpirationDays);
      }

      setSettings(newSettings);
  };

  // Batch delete
  const handleDeleteClick = () => {
    if (deleteConfirming) {
        // ACTUAL DELETE
        // Create new array excluding selected IDs
        const remainingVisits = visits.filter(v => !selectedIds.has(v.id));

        // Clear calc for remaining
        const cleared = clearCalculation(remainingVisits);

        // Update state with new array reference
        setVisits(reindexVisits(cleared));
        setSelectedIds(new Set());
        setDeleteConfirming(false);
    } else {
        // ASK CONFIRMATION
        setDeleteConfirming(true);
        // Auto-reset after 4 seconds
        setTimeout(() => setDeleteConfirming(false), 4000);
    }
  };

  // Single row delete
  const handleDeleteRow = (id: string) => {
      const remaining = visits.filter(v => v.id !== id);
      const cleared = clearCalculation(remaining);
      setVisits(reindexVisits(cleared));

      // Clean up selection if needed
      if (selectedIds.has(id)) {
          const newSelected = new Set(selectedIds);
          newSelected.delete(id);
          setSelectedIds(newSelected);
      }
  };

  const handleExcelUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      const parsed = await parseVisitsExcel(file);
      // Generate IDs first
      let newVisits = parsed.map(v => ({ ...v, id: uuid(), isSkipped: false }));

      // Validate Addresses Immediately
      const validatedVisits = await Promise.all(newVisits.map(async (v) => {
          const check = await checkAddress(v.address);
          return {
              ...v,
              address: v.address, // CHANGE: Keep raw address, do not use check.formattedAddress
              isAddressValid: check.isValid
          };
      }));

      const combined = [...visits, ...validatedVisits];
      // Sort combined by order property initially to respect Excel order, then reindex
      const sorted = combined.sort((a, b) => a.order - b.order);
      const cleared = clearCalculation(sorted);

      setVisits(reindexVisits(cleared));
      alert(`Successfully added ${validatedVisits.length} visits from Excel.`);
    } catch (err: any) {
      alert(`Import failed: ${err.message}`);
    } finally {
      // Reset input so same file can be selected again if needed
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  // --- Logic: Calculation ---

  /**
   * Run the calculation process.
   * @param visitsOverride Optional list of visits to process (e.g. from optimization results). If not provided, uses current state.
   * @param commitOdometer If true, updates totalOdometer fields and global settings. If false, only calculates distance/time (Sim mode).
   */
  const runCalculation = async (visitsOverride?: Visit[], commitOdometer: boolean = true) => {
    if (!isApiReady) return alert("API Key Missing. Please enter your Google Maps API Key in Settings.");

    // Determine which list to use
    const sourceVisits = visitsOverride || visits;
    const activeVisits = sourceVisits.filter(v => !v.isSkipped);

    if (activeVisits.length === 0) return alert("No active visits to calculate.");
    if (!settings.startAddress) return alert("Start address is required.");

    setCalcStatus(CalculationStatus.VALIDATING);
    setErrorMsg(null);
    setStartTrip(null);
    setReturnTrip(null);

    // Work with a copy of all visits
    const processingAllVisits = [...sourceVisits];

    let currentOdo = settings.currentOdometer;
    let currentLoc = settings.startAddress;
    let returnDest = settings.startAddress; 

    // --- TIMETABLE INITIALIZATION ---
    let currentClock = settings.departureTime || "08:00:00";

    // Set Start Trip Data immediately
    // If we aren't committing, start trip odometer is just current setting (visual only)
    const initialStartData: StartTrip = {
        address: settings.startAddress,
        odometer: settings.currentOdometer
    };

    const totalSteps = activeVisits.length + (settings.isStrictMode ? activeVisits.length + 1 : 1); 
    let stepCount = 0;

    const updateProgress = (msg: string) => {
      stepCount++;
      setProgress({ current: stepCount, total: totalSteps, message: msg });
    };

    try {
      // 1. Validation Phase (Strict Mode)
      if (settings.isStrictMode) {
        // Validate Start Address only if not already valid
        if (!settings.isStartValid) {
            updateProgress("Validating Start Address...");
            const validStart = await validateAddressStrict(settings.startAddress);
            currentLoc = validStart;
            returnDest = validStart;
        }

        // Validate Visits only if not already valid
        for (let i = 0; i < processingAllVisits.length; i++) {
          if (processingAllVisits[i].isSkipped) continue;

          const v = processingAllVisits[i];

          if (!v.isAddressValid) {
             updateProgress(`Validating address for ${v.surname}...`);
             // This will throw if invalid, stopping calculation in strict mode
             await validateAddressStrict(v.address); 
             processingAllVisits[i].isAddressValid = true; 
          }
        }
      }

      setStartTrip(initialStartData);
      setCalcStatus(CalculationStatus.ROUTING);

      // 2. Routing Phase
      for (let i = 0; i < processingAllVisits.length; i++) {
        if (processingAllVisits[i].isSkipped) continue;

        const visit = processingAllVisits[i];
        updateProgress(`Routing to ${visit.surname}...`);

        // Use the visit address for routing (Assuming it is valid or raw is good enough)
        // We do not re-validate here to avoid redundant API calls
        const routeDest = visit.address;

        // Call API (Uses LMOD Cache)
        const { distanceKm, durationSeconds } = await getRouteData(currentLoc, routeDest);

        const roundedDist = commercialRound(distanceKm);
        currentOdo += roundedDist;

        // --- UPDATE CLOCK ---
        // 1. Arrive at visit (Previous Clock + Drive Time)
        const arrivalTime = addSecondsToTime(currentClock, durationSeconds);
        // 2. Update Clock for next leg (Arrival + Visit Duration)
        const visitDurationSeconds = (visit.visitDuration || 0) * 60;
        currentClock = addSecondsToTime(arrivalTime, visitDurationSeconds);

        // Update the visit object with results
        processingAllVisits[i].segmentDistance = roundedDist;
        processingAllVisits[i].segmentDuration = durationSeconds;
        processingAllVisits[i].arrivalTime = arrivalTime;

        // Conditionally set Odometer
        if (commitOdometer) {
            processingAllVisits[i].totalOdometer = currentOdo;
        } else {
            processingAllVisits[i].totalOdometer = undefined;
        }

        // Visual update step-by-step
        setVisits([...processingAllVisits]); 

        // Update current location for next leg
        currentLoc = routeDest;

        await sleep(50);
      }

      // 3. Return Trip
      updateProgress("Calculating Return Trip...");
      const { distanceKm: returnDist, durationSeconds: returnDur } = await getRouteData(currentLoc, returnDest);
      const roundedReturn = commercialRound(returnDist);
      currentOdo += roundedReturn;

      // Return arrival is Clock (departure from last visit) + Drive back
      const returnArrivalTime = addSecondsToTime(currentClock, returnDur);

      setReturnTrip({
        address: settings.startAddress, 
        segmentDistance: roundedReturn,
        segmentDuration: returnDur,
        arrivalTime: returnArrivalTime,
        totalOdometer: commitOdometer ? currentOdo : undefined
      });

      setCalcStatus(CalculationStatus.COMPLETE);

      // Only update global settings if committing
      if (commitOdometer) {
          setSettings(prev => ({ ...prev, currentOdometer: currentOdo }));
      }

    } catch (err: any) {
      console.error(err);
      setErrorMsg(err.message || "An unknown error occurred during calculation.");
      setCalcStatus(CalculationStatus.ERROR);
      setStartTrip(null);
    }
  };


  // --- Logic: Optimization (TSP) ---
  const handleOptimizeRoute = async () => {
      if (!isApiReady) return alert("API Key Missing. Please enter your Google Maps API Key in Settings.");

      const activeVisits = visits.filter(v => !v.isSkipped);
      if (activeVisits.length < 2) return alert("Need at least 2 active visits to optimize.");
      if (!settings.startAddress) return alert("Start address is required.");

      setCalcStatus(CalculationStatus.ROUTING);
      setErrorMsg(null);
      setProgress({ current: 0, total: 100, message: 'Checking cached distances...' });

      try {
          // 1. Gather all unique addresses
          const allAddresses = [settings.startAddress, ...activeVisits.map(v => v.address)];

          // 2. Batch Fetch / Prime Cache
          await ensureMatrixData(allAddresses, (msg) => {
              setProgress(prev => ({ ...prev, message: msg }));
          });

          // 3. Run TSP Solver (Local Algorithm)
          setProgress({ current: 90, total: 100, message: 'Solving Optimal Route...' });
          await sleep(100);

          const optimizedActive = solveTSP(settings.startAddress, activeVisits);

          // 4. Merge back
          const skippedVisits = visits.filter(v => v.isSkipped);
          const newOrder = [...optimizedActive, ...skippedVisits];

          // Reindex and clear previous calc data (clean slate)
          const reindexed = reindexVisits(clearCalculation(newOrder));
          setVisits(reindexed);

          // 5. Run Calculation immediately to fill Route/Time columns
          // Pass commitOdometer = false so we don't save/show Odometer values
          await runCalculation(reindexed, false);

      } catch (err: any) {
          console.error(err);
          setErrorMsg("Optimization failed: " + err.message);
          setCalcStatus(CalculationStatus.ERROR);
      }
  };


  const getProgressWidth = () => {
    if (progress.total === 0) return 0;
    return Math.min(100, Math.floor((progress.current / progress.total) * 100));
  };

  const canVisualize = !!startTrip && visits.some(v => !v.isSkipped && v.segmentDistance !== undefined);

  // Disable actions if any active visit has a known invalid address (red cross) AND strict mode is active
  const shouldDisableActions = settings.isStrictMode && visits.some(v => !v.isSkipped && v.isAddressValid === false);

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900 p-4 md:p-8 transition-colors duration-200">
      <div className="max-w-screen-2xl mx-auto space-y-6">

        {/* Header */}
        <header className="flex flex-col md:flex-row md:items-center justify-between bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 transition-colors">
          <div className="mb-4 md:mb-0">
            <h1 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
              <span className="text-google-blue">OdoCalc</span> Pro
            </h1>
            <p className="text-gray-500 dark:text-gray-400 text-xs flex items-center gap-1">
                Serverless Odometer Planning
                {isApiReady ? (
                    <span className="text-green-500 flex items-center" title="API Ready">
                        <svg className="w-3 h-3" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M5 9V7a5 5 0 0110 0v2a2 2 0 012 2v5a2 2 0 01-2 2H5a2 2 0 01-2-2v-5a2 2 0 012-2zm8-2v2H7V7a3 3 0 016 0z" clipRule="evenodd" /></svg>
                    </span>
                ) : (
                    <span className="text-red-500 flex items-center cursor-pointer hover:underline" onClick={() => setIsSettingsOpen(true)} title="API Missing - Click to set Key">
                        <svg className="w-3 h-3" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                        <span className="ml-1">Key Missing</span>
                    </span>
                )}
            </p>
          </div>

          <div className="flex flex-wrap items-center gap-3">
             <input 
              type="file" 
              ref={fileInputRef}
              accept=".xlsx"
              className="hidden"
              onChange={handleExcelUpload}
            />
            <input
              type="file"
              ref={importDbInputRef}
              accept=".json"
              className="hidden"
              onChange={handleImportDB}
            />

            {/* Storage Tools & Settings Group */}
            <div className="flex items-center gap-1 bg-gray-50 dark:bg-gray-700/50 p-1 rounded-lg border border-gray-200 dark:border-gray-600">
                <button
                    type="button"
                    onClick={handleExportDB}
                    className="p-2 text-gray-600 dark:text-gray-300 hover:bg-white dark:hover:bg-gray-600 rounded-md transition-all shadow-sm"
                    title="Export Database (Backup)"
                >
                    {/* Icon: Arrow pointing Out/Up */}
                    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" /></svg>
                </button>
                <button
                    type="button"
                    onClick={() => importDbInputRef.current?.click()}
                    className="p-2 text-gray-600 dark:text-gray-300 hover:bg-white dark:hover:bg-gray-600 rounded-md transition-all shadow-sm"
                    title="Import Database (Restore)"
                >
                    {/* Icon: Arrow pointing In/Down */}
                    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                </button>
                <div className="w-px h-5 bg-gray-300 dark:bg-gray-500 mx-1"></div>
                <button
                    type="button"
                    onClick={handleClearDB}
                    className={`p-2 rounded-md transition-all shadow-sm ${dbDeleteConfirming ? 'bg-red-100 text-red-600 dark:bg-red-900/40 dark:text-red-400' : 'text-gray-600 dark:text-gray-300 hover:bg-white dark:hover:bg-gray-600'}`}
                    title={dbDeleteConfirming ? "Confirm Factory Reset?" : "Clear Database (Factory Reset)"}
                >
                    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                </button>
                <div className="w-px h-5 bg-gray-300 dark:bg-gray-500 mx-1"></div>
                <button 
                  type="button"
                  onClick={() => setIsSettingsOpen(true)}
                  className={`p-2 rounded-md transition-all shadow-sm ${!isApiReady ? 'text-red-500 bg-red-50 dark:bg-red-900/20 animate-pulse' : 'text-gray-600 dark:text-gray-300 hover:bg-white dark:hover:bg-gray-600'}`}
                  title="Settings"
                >
                  <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                </button>
            </div>
          </div>
        </header>

        {/* Main Content Area */}
        <div className="space-y-4">

            {/* Error Message */}
            {calcStatus === CalculationStatus.ERROR && errorMsg && (
              <div className="bg-red-50 dark:bg-red-900/30 border border-red-200 dark:border-red-800 text-red-700 dark:text-red-300 p-4 rounded-lg flex items-center gap-3 animate-fade-in">
                 <svg className="w-5 h-5 flex-shrink-0" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" /></svg>
                 <span>{errorMsg}</span>
              </div>
            )}

            {/* Operational Toolbar (Immediately above list) */}
            <div className="flex flex-col md:flex-row justify-between items-center gap-4 py-2">
                <div className="flex flex-wrap items-center gap-2 w-full md:w-auto">

                    {/* New Visit (Swapped to first) */}
                    <button 
                      type="button"
                      onClick={handleAdd}
                      className="px-4 py-2 bg-green-600 hover:bg-green-700 text-white rounded-lg font-medium text-sm transition-colors shadow-sm flex items-center gap-2"
                      title="New Visit"
                    >
                      <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                      <span>New Visit</span>
                    </button>

                    {/* Import Excel (Swapped to second) */}
                    <button 
                      type="button"
                      onClick={() => fileInputRef.current?.click()}
                      className="px-3 py-2 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-200 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700 font-medium text-sm transition-colors flex items-center gap-2 shadow-sm"
                      title="Import Excel"
                    >
                      <svg className="w-5 h-5 text-green-600 dark:text-green-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                      <span className="hidden md:inline">Import Excel</span>
                    </button>

                    {/* Batch Delete */}
                    {selectedIds.size > 0 && (
                        <button 
                            type="button"
                            onClick={handleDeleteClick}
                            className={`px-3 py-2 border rounded-lg font-medium text-sm transition-colors shadow-sm
                                ${deleteConfirming 
                                    ? 'bg-red-600 text-white border-red-700 hover:bg-red-700' 
                                    : 'bg-white dark:bg-gray-800 text-red-600 dark:text-red-400 border-gray-300 dark:border-gray-600 hover:bg-red-50 dark:hover:bg-red-900/20'}`}
                        >
                            {deleteConfirming ? 'Confirm?' : `Delete (${selectedIds.size})`}
                        </button>
                    )}
                </div>

                <div className="flex items-center gap-2 w-full md:w-auto justify-end">
                    <button
                        type="button"
                        onClick={() => setIsMapOpen(!isMapOpen)}
                        disabled={!canVisualize}
                        className={`px-3 py-2 text-white rounded-lg font-medium text-sm transition-colors shadow-sm flex items-center gap-2
                        ${!canVisualize
                          ? 'bg-gray-400 cursor-not-allowed' 
                          : 'bg-teal-600 hover:bg-teal-700'}`}
                        title="Visualize Route on Map"
                    >
                        <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 20l-5.447-2.724A1 1 0 013 16.382V5.618a1 1 0 011.447-.894L9 7m0 13l6-3m-6 3V7m6 10l4.553 2.276A1 1 0 0021 18.382V7.618a1 1 0 00-.553-.894L15 4m0 13V4m0 0L9 7" /></svg>
                        <span className="hidden md:inline">{isMapOpen ? 'Hide Map' : 'Visualize'}</span>
                    </button>

                    <button
                        type="button"
                        onClick={handleOptimizeRoute}
                        disabled={calcStatus === CalculationStatus.ROUTING || calcStatus === CalculationStatus.VALIDATING || shouldDisableActions}
                        className={`px-3 py-2 text-white rounded-lg font-medium text-sm transition-colors shadow-sm flex items-center gap-2
                        ${calcStatus === CalculationStatus.ROUTING || calcStatus === CalculationStatus.VALIDATING || shouldDisableActions
                          ? 'bg-gray-400 cursor-not-allowed' 
                          : 'bg-indigo-600 hover:bg-indigo-700'}`}
                        title={shouldDisableActions ? "Fix invalid addresses (red cross) before optimizing" : "Calculate Optimal Route"}
                    >
                        <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                        <span className="hidden md:inline">Optimal</span>
                    </button>

                    <button 
                      type="button"
                      onClick={() => runCalculation(undefined, true)}
                      disabled={calcStatus === CalculationStatus.ROUTING || calcStatus === CalculationStatus.VALIDATING || shouldDisableActions}
                      className={`px-4 py-2 text-white rounded-lg font-medium text-sm transition-colors shadow-sm flex items-center gap-2
                        ${calcStatus === CalculationStatus.ROUTING || calcStatus === CalculationStatus.VALIDATING || shouldDisableActions
                          ? 'bg-gray-400 cursor-not-allowed' 
                          : 'bg-google-blue hover:bg-blue-700'}`}
                       title={shouldDisableActions ? "Fix invalid addresses (red cross) before calculating" : "Calculate Route (Standard)"}
                    >
                      {calcStatus === CalculationStatus.ROUTING ? (
                         <svg className="animate-spin w-5 h-5" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                      ) : (
                         <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 17v-2m3 2v-4m3 4v-6m2 10H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                      )}
                      <span>Calculate</span>
                    </button>
                </div>
            </div>

            {/* The Main Table */}
            <VisitList 
              visits={visits}
              startTrip={startTrip}
              returnTrip={returnTrip}
              selectedIds={selectedIds}
              onEdit={handleEdit}
              onReorder={handleReorder}
              onToggleSkip={handleToggleSkip}
              onDelete={handleDeleteRow}
              onToggleSelect={(id) => {
                const newSet = new Set(selectedIds);
                if (newSet.has(id)) newSet.delete(id);
                else newSet.add(id);
                setSelectedIds(newSet);
              }}
              onToggleAll={(checked) => {
                if (checked) setSelectedIds(new Set(visits.map(v => v.id)));
                else setSelectedIds(new Set());
              }}
            />

            {/* Progress Bar (Relocated Below List) */}
            {(calcStatus === CalculationStatus.VALIDATING || calcStatus === CalculationStatus.ROUTING) && (
              <div className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-blue-100 dark:border-gray-700 animate-fade-in-down mb-4">
                <div className="flex justify-between mb-2">
                   <span className="text-sm font-semibold text-google-blue">{progress.message}</span>
                   <span className="text-xs text-gray-500 dark:text-gray-400">{Math.round(getProgressWidth())}%</span>
                </div>
                <div className="w-full bg-gray-200 dark:bg-gray-700 rounded-full h-2">
                  <div 
                    className="bg-google-blue h-2 rounded-full transition-all duration-300 ease-out" 
                    style={{ width: `${getProgressWidth()}%` }}
                  ></div>
                </div>
              </div>
            )}

            {/* Embedded Map Section */}
            <MapSection
              isOpen={isMapOpen}
              onClose={() => setIsMapOpen(false)}
              startTrip={startTrip}
              visits={visits}
            />
        </div>
      </div>

      {/* Modals */}
      <VisitModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onSave={saveVisit}
        initialData={editingVisit}
      />
      <SettingsModal
        isOpen={isSettingsOpen}
        onClose={() => setIsSettingsOpen(false)}
        settings={settings}
        onSave={saveSettings}
      />
    </div>
  );
};

export default App;

export interface Visit {
  id: string; // Unique ID for React keys and selection tracking
  name: string;
  surname: string;
  address: string;
  order: number;
  visitDuration: number; // Duration of the visit in minutes (service time)
  isSkipped?: boolean; // New field to exclude from calculation
  isAddressValid?: boolean; // New field for instant validation status
  // Calculated fields (optional)
  segmentDistance?: number;
  exactDistanceKm?: number; // Unrounded distance
  segmentDuration?: number; // seconds
  arrivalTime?: string; // Calculated time of arrival (HH:mm:ss)
  totalOdometer?: number;
}

// Start trip data (Start of the journey)
export interface StartTrip {
  address: string;
  odometer: number;
}

// Return trip data (End of the journey)
export interface ReturnTrip {
  address: string;
  segmentDistance: number;
  exactDistanceKm?: number; // Unrounded distance
  segmentDuration: number;
  arrivalTime?: string; // Calculated time of arrival back at base
  totalOdometer?: number;
}

export interface AppSettings {
  startAddress: string;
  currentOdometer: number;
  departureTime: string; // HH:mm:ss
  isStrictMode: boolean;
  isStartValid?: boolean; // Track if start address is validated
  isDarkMode: boolean; // Dark mode toggle
  googleApiKey?: string; // User provided API Key (Unencrypted)
  cacheExpirationDays?: number; // Cache expiration in days
}

export enum CalculationStatus {
  IDLE = 'IDLE',
  VALIDATING = 'VALIDATING',
  ROUTING = 'ROUTING',
  COMPLETE = 'COMPLETE',
  ERROR = 'ERROR'
}

import React, { useState, useEffect, useRef } from 'react';
import { Visit, AppSettings, CalculationStatus, ReturnTrip, StartTrip } from './types';
import { VisitList } from './components/VisitList';
import { VisitModal } from './components/VisitModal';
import { SettingsModal } from './components/SettingsModal';
import { MapSection } from './components/MapModal';
import { parseVisitsExcel } from './services/excelService';
import { getRouteData, validateAddressStrict, checkAddress, ensureMatrixData, setRuntimeApiKey, loadGoogleMapsScript } from './services/googleMapsService';
import { solveTSP } from './services/tspSolver';
import { setCacheExpirationDays } from './services/distanceCache';

// Helper for generating IDs
const uuid = () => Math.random().toString(36).substring(2, 9);
const commercialRound = (num: number) => Math.floor(num + 0.5);
const sleep = (ms: number) => new Promise(r => setTimeout(r, ms));

// Helper for Time Arithmetic (HH:mm:ss + seconds)
const addSecondsToTime = (timeStr: string, secondsToAdd: number): string => {
    if (!timeStr) return "00:00:00";
    const [h, m, s] = timeStr.split(':').map(Number);
    const date = new Date();
    date.setHours(h, m, s, 0);
    date.setSeconds(date.getSeconds() + secondsToAdd);

    const hh = date.getHours().toString().padStart(2, '0');
    const mm = date.getMinutes().toString().padStart(2, '0');
    const ss = date.getSeconds().toString().padStart(2, '0');
    return `${hh}:${mm}:${ss}`;
};

const App: React.FC = () => {
  // --- State: Data ---
  const [visits, setVisits] = useState<Visit[]>([]);
  const [startTrip, setStartTrip] = useState<StartTrip | null>(null);
  const [returnTrip, setReturnTrip] = useState<ReturnTrip | null>(null);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  // --- State: Settings ---
  const [settings, setSettings] = useState<AppSettings>({
    startAddress: "Dlouhá 1113, 530 06 Pardubice, Česko",
    currentOdometer: 0,
    departureTime: "08:00:00", // Default Departure
    isStrictMode: false,
    isStartValid: false,
    isDarkMode: true,
    googleApiKey: '',
    cacheExpirationDays: 30
  });

  // --- State: UI ---
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isMapOpen, setIsMapOpen] = useState(false);
  const [editingVisit, setEditingVisit] = useState<Visit | null>(null);
  const [calcStatus, setCalcStatus] = useState<CalculationStatus>(CalculationStatus.IDLE);
  const [progress, setProgress] = useState({ current: 0, total: 0, message: '' });
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [deleteConfirming, setDeleteConfirming] = useState(false);
  const [dbDeleteConfirming, setDbDeleteConfirming] = useState(false);
  const [isApiReady, setIsApiReady] = useState(false);

  // Hidden file input refs
  const fileInputRef = useRef<HTMLInputElement>(null);
  const importDbInputRef = useRef<HTMLInputElement>(null);

  // --- Persistence & API Initialization ---
  useEffect(() => {
    // Load on mount
    const savedVisits = localStorage.getItem('odocalc_visits');
    const savedSettings = localStorage.getItem('odocalc_settings');
    const savedStart = localStorage.getItem('odocalc_start');
    const savedReturn = localStorage.getItem('odocalc_return');

    if (savedVisits) {
      try {
        setVisits(JSON.parse(savedVisits));
      } catch (e) { console.error("Failed to load visits", e); }
    }

    if (savedSettings) {
      try {
        const loaded = JSON.parse(savedSettings);
        // Ensure new fields exist if loading old data
        if (!loaded.departureTime) loaded.departureTime = "08:00:00";
        // Set default cache expiration if missing
        if (!loaded.cacheExpirationDays) loaded.cacheExpirationDays = 30;

        setSettings(loaded);

        // Apply Cache Expiration
        setCacheExpirationDays(loaded.cacheExpirationDays);

        // --- Initialize API Key ---
        if (loaded.googleApiKey) {
            setRuntimeApiKey(loaded.googleApiKey);
            loadGoogleMapsScript(loaded.googleApiKey)
                .then(() => setIsApiReady(true))
                .catch(e => {
                    console.error("API Load Error:", e);
                    setIsApiReady(false);
                });
        }
      } catch (e) { console.error("Failed to load settings", e); }
    } else {
        setRuntimeApiKey("");
        setIsApiReady(false);
        // Prompt user to set key? Could auto-open settings here.
    }

    if (savedStart) {
        try {
            setStartTrip(JSON.parse(savedStart));
        } catch (e) { console.error("Failed to load start trip", e); }
    }

    if (savedReturn) {
        try {
            setReturnTrip(JSON.parse(savedReturn));
        } catch (e) { console.error("Failed to load return trip", e); }
    }
  }, []);

  useEffect(() => {
    // Save on change
    localStorage.setItem('odocalc_visits', JSON.stringify(visits));
    localStorage.setItem('odocalc_settings', JSON.stringify(settings));
    if (startTrip) localStorage.setItem('odocalc_start', JSON.stringify(startTrip));
    else localStorage.removeItem('odocalc_start');

    if (returnTrip) localStorage.setItem('odocalc_return', JSON.stringify(returnTrip));
    else localStorage.removeItem('odocalc_return');

    // Apply Dark Mode
    if (settings.isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [visits, settings, startTrip, returnTrip]);

  // Reset delete confirmation when selection changes
  useEffect(() => {
    setDeleteConfirming(false);
  }, [selectedIds]);

  // --- Helper: Clear Calculations ---
  const clearCalculation = (currentList: Visit[] = visits) => {
    const cleared = currentList.map(v => {
        const { segmentDistance, exactDistanceKm, segmentDuration, totalOdometer, arrivalTime, ...rest } = v;
        return rest as Visit; // Remove calc fields
    });
    setStartTrip(null);
    setReturnTrip(null);
    setCalcStatus(CalculationStatus.IDLE);
    // Auto-close map when clearing calc (since route is gone)
    if (isMapOpen) setIsMapOpen(false); 
    return cleared;
  };

  // --- Data Management (Export/Import/Delete DB) ---

  const handleExportDB = () => {
      try {
          // Parse existing items to objects so final JSON is clean (not double stringified)
          const getParsed = (key: string) => {
              const val = localStorage.getItem(key);
              return val ? JSON.parse(val) : null;
          };

          const exportData = {
              visits: getParsed('odocalc_visits'),
              settings: getParsed('odocalc_settings'),
              start: getParsed('odocalc_start'),
              return: getParsed('odocalc_return'),
              lmod: getParsed('odocalc_lmod'), // Include LMOD Cache
              timestamp: new Date().toISOString()
          };

          const blob = new Blob([JSON.stringify(exportData, null, 2)], { type: 'application/json' });
          const url = URL.createObjectURL(blob);
          const link = document.createElement('a');
          link.href = url;
          link.download = `odocalc-backup-${new Date().toISOString().slice(0,10)}.json`;
          document.body.appendChild(link);
          link.click();
          document.body.removeChild(link);
          URL.revokeObjectURL(url);
      } catch (err: any) {
          alert("Export failed: " + err.message);
      }
  };

  const handleImportDB = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (event) => {
          try {
              const text = event.target?.result as string;
              const data = JSON.parse(text);

              // Basic validation
              if (!data.visits && !data.settings) {
                  throw new Error("Invalid backup file format");
              }

              // Restore LMOD Cache directly to LocalStorage (bypassing React State)
              if (data.lmod) {
                  localStorage.setItem('odocalc_lmod', JSON.stringify(data.lmod));
              }

              // Restore App State
              if (data.settings) setSettings(data.settings);

              if (data.visits) {
                  setVisits(data.visits);
                  setStartTrip(data.start || null);
                  setReturnTrip(data.return || null);
              }

              // Handle Key Restore
              if (data.settings?.googleApiKey) {
                  setRuntimeApiKey(data.settings.googleApiKey);
                  loadGoogleMapsScript(data.settings.googleApiKey)
                    .then(() => setIsApiReady(true))
                    .catch(() => setIsApiReady(false));
              }

              alert("Import successful! Database updated.");

          } catch (err: any) {
              alert("Import failed: " + err.message);
          }
      };
      reader.readAsText(file);

      // Reset input
      if (importDbInputRef.current) importDbInputRef.current.value = '';
  };

  const handleClearDB = () => {
      if (dbDeleteConfirming) {
          // Clear LMOD Cache
          localStorage.removeItem('odocalc_lmod');

          // Reset State to Defaults
          setVisits([]);
          setStartTrip(null);
          setReturnTrip(null);
          setSettings({
            startAddress: "Dlouhá 1113, 530 06 Pardubice, Česko",
            currentOdometer: 0,
            departureTime: "08:00:00",
            isStrictMode: false,
            isStartValid: false,
            isDarkMode: true,
            googleApiKey: '', // Reset Key
            cacheExpirationDays: 30
          });

          setRuntimeApiKey("");
          setIsApiReady(false);
          setCacheExpirationDays(30); // Reset cache config

          setDbDeleteConfirming(false);
          alert("Database cleared (Factory Reset). API Key removed.");
      } else {
          setDbDeleteConfirming(true);
          setTimeout(() => setDbDeleteConfirming(false), 4000);
      }
  };

  // --- Actions ---

  const reindexVisits = (list: Visit[]) => {
    let orderCounter = 1;
    return list.map((v) => {
        // If skipped, set order to 0 (or keep internal track, but UI expects 0 to show empty)
        if (v.isSkipped) {
            return { ...v, order: 0 };
        }
        return { ...v, order: orderCounter++ };
    });
  };

  const handleReorder = (newVisits: Visit[]) => {
    // Reorder clears calculation
    const cleared = clearCalculation(newVisits);
    setVisits(reindexVisits(cleared));
  };

  const handleToggleSkip = (id: string) => {
      // Toggle skipped status
      const updated = visits.map(v => v.id === id ? { ...v, isSkipped: !v.isSkipped } : v);
      // Logic requires route recalculation because a stop is added/removed
      const cleared = clearCalculation(updated);
      setVisits(reindexVisits(cleared));
  };

  const handleAdd = () => {
    setEditingVisit(null);
    setIsModalOpen(true);
  };

  const handleEdit = (visit: Visit) => {
    setEditingVisit(visit);
    setIsModalOpen(true);
  };

  const saveVisit = (data: Omit<Visit, 'id'>) => {
    let newList;
    if (editingVisit) {
      // Update existing
      newList = visits.map(v => v.id === editingVisit.id ? { ...v, ...data } : v);
    } else {
      // Create new
      const newVisit = { ...data, id: uuid(), order: 0, isSkipped: false }; // Order will be set by reindex
      newList = [...visits, newVisit];
    }
    const cleared = clearCalculation(newList);
    setVisits(reindexVisits(cleared));
    setIsModalOpen(false);
  };

  const saveSettings = (newSettings: AppSettings) => {
      // If start address or odometer changed, invalidate results
      if (newSettings.startAddress !== settings.startAddress || newSettings.currentOdometer !== settings.currentOdometer || newSettings.departureTime !== settings.departureTime) {
          const cleared = clearCalculation(visits);
          setVisits(cleared);
      }

      // Check Key Change
      if (newSettings.googleApiKey !== settings.googleApiKey) {
          if (newSettings.googleApiKey) {
              setRuntimeApiKey(newSettings.googleApiKey);
              loadGoogleMapsScript(newSettings.googleApiKey)
                .then(() => setIsApiReady(true))
                .catch(e => {
                    console.error(e);
                    setIsApiReady(false);
                    alert("Failed to load Maps API with this key.");
                });
          } else {
              setRuntimeApiKey("");
              setIsApiReady(false);
          }
      }

      // Update Cache Config
      if (newSettings.cacheExpirationDays && newSettings.cacheExpirationDays !== settings.cacheExpirationDays) {
          setCacheExpirationDays(newSettings.cacheExpirationDays);
      }

      setSettings(newSettings);
  };

  // Batch delete
  const handleDeleteClick = () => {
    if (deleteConfirming) {
        // ACTUAL DELETE
        // Create new array excluding selected IDs
        const remainingVisits = visits.filter(v => !selectedIds.has(v.id));

        // Clear calc for remaining
        const cleared = clearCalculation(remainingVisits);

        // Update state with new array reference
        setVisits(reindexVisits(cleared));
        setSelectedIds(new Set());
        setDeleteConfirming(false);
    } else {
        // ASK CONFIRMATION
        setDeleteConfirming(true);
        // Auto-reset after 4 seconds
        setTimeout(() => setDeleteConfirming(false), 4000);
    }
  };

  // Single row delete
  const handleDeleteRow = (id: string) => {
      const remaining = visits.filter(v => v.id !== id);
      const cleared = clearCalculation(remaining);
      setVisits(reindexVisits(cleared));

      // Clean up selection if needed
      if (selectedIds.has(id)) {
          const newSelected = new Set(selectedIds);
          newSelected.delete(id);
          setSelectedIds(newSelected);
      }
  };

  const handleExcelUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      const parsed = await parseVisitsExcel(file);
      // Generate IDs first
      let newVisits = parsed.map(v => ({ ...v, id: uuid(), isSkipped: false }));

      // Validate Addresses Immediately
      const validatedVisits = await Promise.all(newVisits.map(async (v) => {
          const check = await checkAddress(v.address);
          return {
              ...v,
              address: v.address, // CHANGE: Keep raw address, do not use check.formattedAddress
              isAddressValid: check.isValid
          };
      }));

      const combined = [...visits, ...validatedVisits];
      // Sort combined by order property initially to respect Excel order, then reindex
      const sorted = combined.sort((a, b) => a.order - b.order);
      const cleared = clearCalculation(sorted);

      setVisits(reindexVisits(cleared));
      alert(`Successfully added ${validatedVisits.length} visits from Excel.`);
    } catch (err: any) {
      alert(`Import failed: ${err.message}`);
    } finally {
      // Reset input so same file can be selected again if needed
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  // --- Logic: Calculation ---

  /**
   * Run the calculation process.
   * @param visitsOverride Optional list of visits to process (e.g. from optimization results). If not provided, uses current state.
   * @param commitOdometer If true, updates totalOdometer fields and global settings. If false, only calculates distance/time (Sim mode).
   */
  const runCalculation = async (visitsOverride?: Visit[], commitOdometer: boolean = true) => {
    if (!isApiReady) return alert("API Key Missing. Please enter your Google Maps API Key in Settings.");

    // Determine which list to use
    const sourceVisits = visitsOverride || visits;
    const activeVisits = sourceVisits.filter(v => !v.isSkipped);

    if (activeVisits.length === 0) return alert("No active visits to calculate.");
    if (!settings.startAddress) return alert("Start address is required.");

    setCalcStatus(CalculationStatus.VALIDATING);
    setErrorMsg(null);
    setStartTrip(null);
    setReturnTrip(null);

    // Work with a copy of all visits
    const processingAllVisits = [...sourceVisits];

    let currentOdo = settings.currentOdometer;
    let currentLoc = settings.startAddress;
    let returnDest = settings.startAddress; 

    // --- TIMETABLE INITIALIZATION ---
    let currentClock = settings.departureTime || "08:00:00";

    // Set Start Trip Data immediately
    // If we aren't committing, start trip odometer is just current setting (visual only)
    const initialStartData: StartTrip = {
        address: settings.startAddress,
        odometer: settings.currentOdometer
    };

    const totalSteps = activeVisits.length + (settings.isStrictMode ? activeVisits.length + 1 : 1); 
    let stepCount = 0;

    const updateProgress = (msg: string) => {
      stepCount++;
      setProgress({ current: stepCount, total: totalSteps, message: msg });
    };

    try {
      // 1. Validation Phase (Strict Mode)
      if (settings.isStrictMode) {
        // Validate Start Address only if not already valid
        if (!settings.isStartValid) {
            updateProgress("Validating Start Address...");
            const validStart = await validateAddressStrict(settings.startAddress);
            currentLoc = validStart;
            returnDest = validStart;
        }

        // Validate Visits only if not already valid
        for (let i = 0; i < processingAllVisits.length; i++) {
          if (processingAllVisits[i].isSkipped) continue;

          const v = processingAllVisits[i];

          if (!v.isAddressValid) {
             updateProgress(`Validating address for ${v.surname}...`);
             // This will throw if invalid, stopping calculation in strict mode
             await validateAddressStrict(v.address); 
             processingAllVisits[i].isAddressValid = true; 
          }
        }
      }

      setStartTrip(initialStartData);
      setCalcStatus(CalculationStatus.ROUTING);

      // 2. Routing Phase
      for (let i = 0; i < processingAllVisits.length; i++) {
        if (processingAllVisits[i].isSkipped) continue;

        const visit = processingAllVisits[i];
        updateProgress(`Routing to ${visit.surname}...`);

        // Use the visit address for routing (Assuming it is valid or raw is good enough)
        // We do not re-validate here to avoid redundant API calls
        const routeDest = visit.address;

        // Call API (Uses LMOD Cache)
        const { distanceKm, durationSeconds } = await getRouteData(currentLoc, routeDest);

        const roundedDist = commercialRound(distanceKm);
        currentOdo += roundedDist;

        // --- UPDATE CLOCK ---
        // 1. Arrive at visit (Previous Clock + Drive Time)
        const arrivalTime = addSecondsToTime(currentClock, durationSeconds);
        // 2. Update Clock for next leg (Arrival + Visit Duration)
        const visitDurationSeconds = (visit.visitDuration || 0) * 60;
        currentClock = addSecondsToTime(arrivalTime, visitDurationSeconds);

        // Update the visit object with results
        processingAllVisits[i].segmentDistance = roundedDist;
        processingAllVisits[i].exactDistanceKm = distanceKm; // Store exact unrounded
        processingAllVisits[i].segmentDuration = durationSeconds;
        processingAllVisits[i].arrivalTime = arrivalTime;

        // Conditionally set Odometer
        if (commitOdometer) {
            processingAllVisits[i].totalOdometer = currentOdo;
        } else {
            processingAllVisits[i].totalOdometer = undefined;
        }

        // Visual update step-by-step
        setVisits([...processingAllVisits]); 

        // Update current location for next leg
        currentLoc = routeDest;

        await sleep(50);
      }

      // 3. Return Trip
      updateProgress("Calculating Return Trip...");
      const { distanceKm: returnDist, durationSeconds: returnDur } = await getRouteData(currentLoc, returnDest);
      const roundedReturn = commercialRound(returnDist);
      currentOdo += roundedReturn;

      // Return arrival is Clock (departure from last visit) + Drive back
      const returnArrivalTime = addSecondsToTime(currentClock, returnDur);

      setReturnTrip({
        address: settings.startAddress, 
        segmentDistance: roundedReturn,
        exactDistanceKm: returnDist, // Store exact unrounded
        segmentDuration: returnDur,
        arrivalTime: returnArrivalTime,
        totalOdometer: commitOdometer ? currentOdo : undefined
      });

      setCalcStatus(CalculationStatus.COMPLETE);

      // Only update global settings if committing
      if (commitOdometer) {
          setSettings(prev => ({ ...prev, currentOdometer: currentOdo }));
      }

    } catch (err: any) {
      console.error(err);
      setErrorMsg(err.message || "An unknown error occurred during calculation.");
      setCalcStatus(CalculationStatus.ERROR);
      setStartTrip(null);
    }
  };


  // --- Logic: Optimization (TSP) ---
  const handleOptimizeRoute = async () => {
      if (!isApiReady) return alert("API Key Missing. Please enter your Google Maps API Key in Settings.");

      const activeVisits = visits.filter(v => !v.isSkipped);
      if (activeVisits.length < 2) return alert("Need at least 2 active visits to optimize.");
      if (!settings.startAddress) return alert("Start address is required.");

      setCalcStatus(CalculationStatus.ROUTING);
      setErrorMsg(null);
      setProgress({ current: 0, total: 100, message: 'Checking cached distances...' });

      try {
          // 1. Gather all unique addresses
          const allAddresses = [settings.startAddress, ...activeVisits.map(v => v.address)];

          // 2. Batch Fetch / Prime Cache
          await ensureMatrixData(allAddresses, (msg) => {
              setProgress(prev => ({ ...prev, message: msg }));
          });

          // 3. Run TSP Solver (Local Algorithm)
          setProgress({ current: 90, total: 100, message: 'Solving Optimal Route...' });
          await sleep(100);

          const optimizedActive = solveTSP(settings.startAddress, activeVisits);

          // 4. Merge back
          const skippedVisits = visits.filter(v => v.isSkipped);
          const newOrder = [...optimizedActive, ...skippedVisits];

          // Reindex and clear previous calc data (clean slate)
          const reindexed = reindexVisits(clearCalculation(newOrder));
          setVisits(reindexed);

          // 5. Run Calculation immediately to fill Route/Time columns
          // Pass commitOdometer = false so we don't save/show Odometer values
          await runCalculation(reindexed, false);

      } catch (err: any) {
          console.error(err);
          setErrorMsg("Optimization failed: " + err.message);
          setCalcStatus(CalculationStatus.ERROR);
      }
  };


  const getProgressWidth = () => {
    if (progress.total === 0) return 0;
    return Math.min(100, Math.floor((progress.current / progress.total) * 100));
  };

  const canVisualize = !!startTrip && visits.some(v => !v.isSkipped && v.segmentDistance !== undefined);

  // Disable actions if any active visit has a known invalid address (red cross) AND strict mode is active
  const shouldDisableActions = settings.isStrictMode && visits.some(v => !v.isSkipped && v.isAddressValid === false);

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900 p-4 md:p-8 transition-colors duration-200">
      <div className="max-w-screen-2xl mx-auto space-y-6">

