import React from 'react';
import { Visit, ReturnTrip, StartTrip } from '../types';
import { translations, Language } from '../services/translations';
import {
  DndContext, 
  closestCenter,
  KeyboardSensor,
  PointerSensor,
  useSensor,
  useSensors,
  DragEndEvent
} from '@dnd-kit/core';
import {
  arrayMove,
  SortableContext,
  sortableKeyboardCoordinates,
  verticalListSortingStrategy,
  useSortable
} from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';

interface VisitListProps {
  visits: Visit[];
  startTrip: StartTrip | null;
  returnTrip: ReturnTrip | null;
  selectedIds: Set<string>;
  onToggleSelect: (id: string) => void;
  onToggleAll: (selected: boolean) => void;
  onEdit: (visit: Visit) => void;
  onReorder: (newVisits: Visit[]) => void;
  onToggleSkip: (id: string) => void;
  onDelete: (id: string) => void;
  lang: Language;
  departureTime: string; // New prop for Start Row Plan column
}

// Helper format function for duration with specific rules:
const formatDuration = (seconds?: number): string => {
    if (seconds === undefined) return '—';
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);

    if (h === 0) {
        return `${m}m`;
    } else {
        return `${h}h ${m.toString().padStart(2, '0')}m`;
    }
};

// Helper format function for exact distance: wrap in brackets (x,xxx)
const formatExactDist = (km?: number): string => {
    if (km === undefined) return '—';
    return `(${km.toFixed(3).replace('.', ',')})`;
};

// Helper to format HH:mm:ss to HH:mm
const formatTime = (timeStr?: string): string => {
    if (!timeStr) return '—';
    return timeStr.slice(0, 5);
};

// --- Sortable Row Component ---
interface SortableRowProps {
  visit: Visit;
  isSelected: boolean;
  onToggleSelect: (id: string) => void;
  onEdit: (visit: Visit) => void;
  onToggleSkip: (id: string) => void;
  onDelete: (id: string) => void;
}

const SortableRow: React.FC<SortableRowProps> = ({ visit, isSelected, onToggleSelect, onEdit, onToggleSkip, onDelete }) => {
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging
  } = useSortable({ id: visit.id });

  const [deleteConfirming, setDeleteConfirming] = React.useState(false);

  const style = {
    transform: CSS.Translate.toString(transform),
    transition,
    zIndex: isDragging ? 50 : 'auto',
    position: isDragging ? 'relative' as const : 'static' as const,
  };

  const hasCalc = visit.segmentDistance !== undefined && !visit.isSkipped;
  const isSkipped = visit.isSkipped;
  const showOdometer = hasCalc && visit.totalOdometer !== undefined;

  return (
    <tr 
      ref={setNodeRef} 
      style={style} 
      onDoubleClick={(e) => {
        if (e.target instanceof HTMLElement) {
             const tagName = e.target.tagName;
             if (tagName !== 'INPUT' && tagName !== 'BUTTON' && tagName !== 'SVG' && tagName !== 'PATH') {
                 onToggleSkip(visit.id);
             }
        }
      }}
      className={`transition-colors cursor-pointer 
        ${isDragging ? 'bg-blue-50 dark:bg-blue-900/30 shadow-lg' : 'hover:bg-gray-50 dark:hover:bg-gray-700 bg-white dark:bg-gray-800'}
        ${isSkipped ? 'opacity-50 grayscale' : 'text-gray-900 dark:text-gray-100'}
      `}
    >
      <td className="px-2 py-1 whitespace-nowrap w-8 text-center">
        <button 
          className="dnd-handle cursor-move text-gray-400 hover:text-gray-600 dark:text-gray-500 dark:hover:text-gray-300 p-1 rounded focus:outline-none"
          {...attributes} 
          {...listeners}
          type="button"
        >
          <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8h16M4 16h16" />
          </svg>
        </button>
      </td>
      <td className="px-2 py-1 whitespace-nowrap w-8 text-center">
        <input
          type="checkbox"
          checked={isSelected}
          onChange={() => onToggleSelect(visit.id)}
          onClick={(e) => e.stopPropagation()}
          onPointerDown={(e) => e.stopPropagation()}
          className="h-4 w-4 text-google-blue focus:ring-google-blue border-gray-300 dark:border-gray-600 rounded cursor-pointer dark:bg-gray-700"
        />
      </td>
      <td className="px-2 py-1 whitespace-nowrap w-8 text-center">
        <button 
          type="button"
          onClick={(e) => { e.stopPropagation(); onToggleSkip(visit.id); }}
          onPointerDown={(e) => e.stopPropagation()}
          className={`p-1 rounded-full transition-colors ${isSkipped ? 'text-red-500 bg-red-50 dark:bg-red-900/20' : 'text-gray-300 dark:text-gray-600 hover:text-gray-500 dark:hover:text-gray-400'}`}
        >
           <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M18.364 18.364A9 9 0 005.636 5.636m12.728 12.728A9 9 0 015.636 5.636m12.728 12.728L5.636 5.636" />
           </svg>
        </button>
      </td>
      <td {...listeners} className="cursor-move px-4 py-1 whitespace-nowrap text-base text-gray-500 dark:text-gray-400 font-mono text-center touch-manipulation">
        {visit.order > 0 ? visit.order : '-'}
      </td>
      <td {...listeners} className="cursor-move px-4 py-1 whitespace-nowrap text-base font-medium text-gray-900 dark:text-white touch-manipulation">
        {visit.name}
      </td>
      <td {...listeners} className="cursor-move px-4 py-1 whitespace-nowrap text-base text-gray-900 dark:text-gray-200 touch-manipulation">
        {visit.surname}
      </td>
      <td {...listeners} className="cursor-move px-4 py-1 whitespace-nowrap text-base text-gray-500 dark:text-gray-400 max-w-xs truncate touch-manipulation" title={visit.address}>
        {visit.address}
      </td>
      <td className="px-2 py-1 whitespace-nowrap text-center">
        {visit.isAddressValid === true && (
            <svg className="w-5 h-5 text-green-500 mx-auto" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
        )}
        {visit.isAddressValid === false && (
            <svg className="w-5 h-5 text-red-500 mx-auto" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
        )}
        {visit.isAddressValid === undefined && (
            <span className="text-gray-300 dark:text-gray-600">-</span>
        )}
      </td>
      <td className={`px-4 py-1 whitespace-nowrap text-base text-right font-mono ${showOdometer ? 'text-gray-900 dark:text-gray-100 font-bold' : 'text-gray-300 dark:text-gray-600'}`}>
        {showOdometer ? visit.totalOdometer : '—'}
      </td>
      <td className={`pl-4 pr-1 py-1 whitespace-nowrap text-base text-right font-mono ${hasCalc ? 'text-google-blue dark:text-blue-400 font-medium' : 'text-gray-300 dark:text-gray-600'}`}>
        {hasCalc ? `+ ${visit.segmentDistance} km` : '—'}
      </td>
      <td className={`pl-1 pr-4 py-1 whitespace-nowrap text-sm text-left font-mono ${hasCalc ? 'text-gray-700 dark:text-gray-300' : 'text-gray-300 dark:text-gray-600'}`}>
        {hasCalc ? formatExactDist(visit.exactDistanceKm) : '—'}
      </td>
      <td className={`px-4 py-1 whitespace-nowrap text-base text-right font-mono ${hasCalc ? 'text-gray-700 dark:text-gray-300' : 'text-gray-300 dark:text-gray-600'}`}>
        {hasCalc ? formatDuration(visit.segmentDuration) : '—'}
      </td>
      <td className={`px-4 py-1 whitespace-nowrap text-base text-right font-mono ${visit.arrivalTime ? 'text-indigo-600 dark:text-indigo-400 font-bold' : 'text-gray-300 dark:text-gray-600'}`}>
         {formatTime(visit.arrivalTime)}
      </td>
      <td className={`px-4 py-1 whitespace-nowrap text-base text-right font-mono ${visit.visitDuration > 0 ? 'text-gray-700 dark:text-gray-300' : 'text-gray-300 dark:text-gray-600'}`}>
         {formatDuration((visit.visitDuration || 0) * 60)}
      </td>
      <td className="px-4 py-1 whitespace-nowrap text-right text-base font-medium">
        <div className="flex justify-end items-center gap-2">
            <button 
              type="button"
              onClick={(e) => { e.stopPropagation(); onEdit(visit); }}
              onPointerDown={(e) => e.stopPropagation()}
              className="text-google-blue dark:text-blue-400 hover:text-blue-900 dark:hover:text-blue-300 p-1 rounded-full hover:bg-blue-50 dark:hover:bg-blue-900/30 transition-colors"
            >
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
              </svg>
            </button>
            <button 
              type="button"
              onClick={(e) => { 
                  e.stopPropagation(); 
                  if (deleteConfirming) {
                      onDelete(visit.id);
                      setDeleteConfirming(false);
                  } else {
                      setDeleteConfirming(true);
                      setTimeout(() => setDeleteConfirming(false), 3000);
                  }
              }}
              onPointerDown={(e) => e.stopPropagation()}
              className={`p-1 rounded-full transition-colors ${deleteConfirming ? 'bg-red-600 text-white hover:bg-red-700 shadow-md' : 'text-red-600 dark:text-red-400 hover:text-red-900 dark:hover:text-red-300 hover:bg-red-50 dark:hover:bg-red-900/30'}`}
            >
              {deleteConfirming ? (
                 <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                 </svg>
              ) : (
                 <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                 </svg>
              )}
            </button>
        </div>
      </td>
    </tr>
  );
};

// --- Main List Component ---
export const VisitList: React.FC<VisitListProps> = ({ 
  visits, 
  startTrip,
  returnTrip,
  selectedIds, 
  onToggleSelect, 
  onToggleAll,
  onEdit,
  onReorder,
  onToggleSkip,
  onDelete,
  lang,
  departureTime
}) => {
  const allSelected = visits.length > 0 && selectedIds.size === visits.length;
  const t = translations[lang];

  const sensors = useSensors(
    useSensor(PointerSensor, {
        activationConstraint: {
            distance: 5,
        },
    }),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    })
  );

  const handleDragEnd = (event: DragEndEvent) => {
    const { active, over } = event;
    if (over && active.id !== over.id) {
      const oldIndex = visits.findIndex((v) => v.id === active.id);
      const newIndex = visits.findIndex((v) => v.id === over.id);
      const newOrder = arrayMove(visits, oldIndex, newIndex);
      onReorder(newOrder);
    }
  };

  const activeVisits = visits.filter(v => !v.isSkipped);
  const totalDistance = activeVisits.reduce((acc, v) => acc + (v.segmentDistance || 0), 0) + (returnTrip?.segmentDistance || 0);
  const totalExactDistance = activeVisits.reduce((acc, v) => acc + (v.exactDistanceKm || 0), 0) + (returnTrip?.exactDistanceKm || 0);
  const totalDuration = activeVisits.reduce((acc, v) => acc + (v.segmentDuration || 0), 0) + (returnTrip?.segmentDuration || 0);
  const totalServiceTime = activeVisits.reduce((acc, v) => acc + (v.visitDuration || 0), 0) * 60; 

  const showTotals = startTrip && (activeVisits.length > 0 || returnTrip);

  return (
    <div className="overflow-x-auto border border-gray-200 dark:border-gray-700 rounded-lg shadow-sm bg-white dark:bg-gray-800 w-full transition-colors">
      <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
        <table className="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
          <thead className="bg-gray-50 dark:bg-gray-900 transition-colors">
            <tr>
              <th scope="col" className="px-2 py-1 w-8"></th>
              <th scope="col" className="px-2 py-1 text-center w-8">
                <input
                  type="checkbox"
                  checked={allSelected}
                  onChange={(e) => onToggleAll(e.target.checked)}
                  className="h-4 w-4 text-google-blue focus:ring-google-blue border-gray-300 dark:border-gray-600 rounded cursor-pointer dark:bg-gray-700"
                />
              </th>
              <th className="px-2 py-1 text-center text-sm font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider w-8">{t.colSkip}</th>
              <th className="px-4 py-1 text-center text-sm font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider w-16">{t.colOrder}</th>
              <th className="px-4 py-1 text-left text-sm font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{t.colName}</th>
              <th className="px-4 py-1 text-left text-sm font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{t.colSurname}</th>
              <th className="px-4 py-1 text-left text-sm font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider w-1/3">{t.colAddress}</th>
              <th className="px-4 py-1 text-center text-sm font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider w-12">{t.colValid}</th>
              <th className="px-4 py-1 text-right text-sm font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider text-gray-800 dark:text-gray-200">{t.colOdometer}</th>
              <th colSpan={2} className="px-4 py-1 text-center text-sm font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider text-google-blue dark:text-blue-400">{t.colDistance}</th>
              <th className="px-4 py-1 text-right text-sm font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{t.colTime}</th>
              <th className="px-4 py-1 text-right text-sm font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider text-indigo-600 dark:text-indigo-400">{t.colPlan}</th>
              <th className="px-4 py-1 text-right text-sm font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{t.colDurat}</th>
              <th className="px-4 py-1 text-right text-sm font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{t.colActions}</th>
            </tr>
          </thead>
          <tbody className="bg-white dark:bg-gray-800 divide-y divide-gray-200 dark:divide-gray-700">

            {startTrip && (
              <tr className="bg-green-50 dark:bg-green-900/20 [&>td]:border-b-1 [&>td]:border-green-500">
                <td></td><td></td><td></td>
                <td className="px-4 py-1 text-center text-base font-bold text-green-700 dark:text-green-400">{t.start}</td>
                <td colSpan={2} className="px-4 py-1 text-base font-bold text-green-700 dark:text-green-400">{t.departure}</td>
                <td className="px-4 py-1 text-base text-green-800 dark:text-green-300 truncate" title={startTrip.address}>{startTrip.address}</td>
                <td className="px-2 py-1 text-center">
                    <svg className="w-5 h-5 text-green-500 mx-auto" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
                </td>
                <td className="px-4 py-1 text-right text-base font-bold text-green-800 dark:text-green-300 font-mono">{startTrip.odometer}</td>
                <td className="pl-4 pr-1 py-1 text-right text-base font-bold text-green-700 dark:text-green-400 font-mono"></td>
                <td className="pl-1 pr-4 py-1 text-left text-base font-bold text-green-700 dark:text-green-400 font-mono"></td>
                <td className="px-4 py-1 text-right text-base font-bold text-green-700 dark:text-green-400 font-mono"></td>
                {/* Plan (Timetable) for Start */}
                <td className="px-4 py-1 text-right text-base font-bold text-green-800 dark:text-green-300 font-mono whitespace-nowrap">
                  {formatTime(departureTime)}
                </td>
                <td className="px-4 py-1 text-right text-base font-bold text-green-700 dark:text-green-400 font-mono"></td>
                <td></td>
              </tr>
            )}

            {visits.length === 0 ? (
              <tr>
                <td colSpan={15} className="px-6 py-10 text-center text-base text-gray-500 dark:text-gray-400 italic">{t.noVisits}</td>
              </tr>
            ) : (
              <SortableContext items={visits.map(v => v.id)} strategy={verticalListSortingStrategy}>
                {visits.map((visit) => (
                  <SortableRow 
                    key={visit.id} visit={visit} isSelected={selectedIds.has(visit.id)}
                    onToggleSelect={onToggleSelect} onEdit={onEdit} onToggleSkip={onToggleSkip} onDelete={onDelete}
                  />
                ))}
              </SortableContext>
            )}

            {returnTrip && visits.length > 0 && (
              <tr className="bg-green-50 dark:bg-green-900/20 [&>td]:border-b-2 [&>td]:border-green-500">
                <td colSpan={3}></td>
                <td className="px-4 py-1 text-center text-base font-bold text-green-700 dark:text-green-400">{t.end}</td>
                <td colSpan={2} className="px-4 py-1 text-base font-bold text-green-700 dark:text-green-400">{t.return}</td>
                <td className="px-4 py-1 text-base text-green-800 dark:text-green-300 truncate" title={returnTrip.address}>{returnTrip.address}</td>
                <td className="px-2 py-1 text-center">
                    <svg className="w-5 h-5 text-green-500 mx-auto" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
                </td>
                <td className="px-4 py-1 text-right text-base font-bold text-green-800 dark:text-green-300 font-mono">{returnTrip.totalOdometer !== undefined ? returnTrip.totalOdometer : '—'}</td>
                <td className="pl-4 pr-1 py-1 whitespace-nowrap text-right text-base font-bold text-green-700 dark:text-green-400 font-mono">+ {returnTrip.segmentDistance} km</td>
                <td className="pl-1 pr-4 py-1 whitespace-nowrap text-left text-sm font-bold text-green-800 dark:text-green-300 font-mono opacity-80">{formatExactDist(returnTrip.exactDistanceKm)}</td>
                 <td className="px-4 py-1 text-right text-base font-bold text-green-700 dark:text-green-400 font-mono">{formatDuration(returnTrip.segmentDuration)}</td>
                <td className="px-4 py-1 text-right text-base font-bold text-green-700 dark:text-green-400 font-mono">{formatTime(returnTrip.arrivalTime)}</td>
                <td className="px-4 py-1 text-right text-base font-bold text-green-700 dark:text-green-400 font-mono"></td>
                <td></td>
              </tr>
            )}

             {showTotals && (
              <tr className="bg-gray-100 dark:bg-gray-800 [&>td]:border-t-4 [&>td]:border-double [&>td]:border-gray-300 dark:[&>td]:border-gray-600">
                <td colSpan={3}></td>
                <td className="px-4 py-2 text-center text-lg font-black text-gray-800 dark:text-white uppercase">{t.total}</td>
                <td colSpan={4}></td>
                <td className="px-4 py-2 text-right text-lg font-bold text-gray-500 dark:text-gray-400 font-mono"></td>
                <td className="pl-4 pr-1 py-2 whitespace-nowrap text-right text-lg font-black text-google-blue dark:text-blue-400 font-mono text-base">{totalDistance} km</td>
                <td className="pl-1 pr-4 py-2 whitespace-nowrap text-left text-lg font-black text-gray-700 dark:text-gray-300 font-mono text-sm">{formatExactDist(totalExactDistance)}</td>
                <td className="px-4 py-2 text-right text-lg font-black text-gray-800 dark:text-gray-100 font-mono text-base whitespace-nowrap">{formatDuration(totalDuration)}</td>
                <td className="px-4 py-2 text-right text-lg font-black text-indigo-600 dark:text-indigo-400 font-mono text-base whitespace-nowrap">{formatTime(returnTrip?.arrivalTime)}</td>
                <td className="px-4 py-2 text-right text-lg font-black text-gray-600 dark:text-gray-400 font-mono text-base whitespace-nowrap">{formatDuration(totalServiceTime)}</td>
                <td></td>
              </tr>
            )}
          </tbody>
        </table>
      </DndContext>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Visit, AppSettings, CalculationStatus, ReturnTrip, StartTrip } from './types';
import { VisitList } from './components/VisitList';
import { VisitModal } from './components/VisitModal';
import { SettingsModal } from './components/SettingsModal';
import { HelpModal } from './components/HelpModal';
import { MapSection } from './components/MapModal';
import { parseVisitsExcel } from './services/excelService';
import { getRouteData, validateAddressStrict, checkAddress, ensureMatrixData, setRuntimeApiKey, loadGoogleMapsScript } from './services/googleMapsService';
import { solveTSP } from './services/tspSolver';
import { setCacheExpirationDays } from './services/distanceCache';
import { translations } from './services/translations';

// --- DEVELOPER CONFIG ---
// Set your API Key here to avoid re-entering it during development.
// Clear this before deployment.
const DEFAULT_DEV_API_KEY = "AIzaSyBCWH72da5n-rq8Qu3sOc64cW_asGZpy0w"; 

// Helper for generating IDs
const uuid = () => Math.random().toString(36).substring(2, 9);
const commercialRound = (num: number) => Math.floor(num + 0.5);
const sleep = (ms: number) => new Promise(r => setTimeout(r, ms));

// Helper for Time Arithmetic (HH:mm:ss + seconds)
const addSecondsToTime = (timeStr: string, secondsToAdd: number): string => {
    if (!timeStr) return "00:00:00";
    const [h, m, s] = timeStr.split(':').map(Number);
    const date = new Date();
    date.setHours(h, m, s, 0);
    date.setSeconds(date.getSeconds() + secondsToAdd);

    const hh = date.getHours().toString().padStart(2, '0');
    const mm = date.getMinutes().toString().padStart(2, '0');
    const ss = date.getSeconds().toString().padStart(2, '0');
    return `${hh}:${mm}:${ss}`;
};

const App: React.FC = () => {
  // --- State: Data ---
  const [visits, setVisits] = useState<Visit[]>([]);
  const [startTrip, setStartTrip] = useState<StartTrip | null>(null);
  const [returnTrip, setReturnTrip] = useState<ReturnTrip | null>(null);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  // --- State: Settings ---
  const [settings, setSettings] = useState<AppSettings>({
    startAddress: "Dlouhá 1113, 530 06 Pardubice, Česko",
    currentOdometer: 0,
    departureTime: "08:00:00", // Default Departure
    isStrictMode: false,
    isStartValid: false,
    isDarkMode: true,
    googleApiKey: DEFAULT_DEV_API_KEY, // Default to Dev Constant
    cacheExpirationDays: 30,
    language: 'cs' // Default to Czech as per user preference (1. Czech)
  });

  // Derived translations
  const t = translations[settings.language];

  // --- State: UI ---
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isHelpOpen, setIsHelpOpen] = useState(false);
  const [isMapOpen, setIsMapOpen] = useState(false);
  const [editingVisit, setEditingVisit] = useState<Visit | null>(null);
  const [calcStatus, setCalcStatus] = useState<CalculationStatus>(CalculationStatus.IDLE);
  const [progress, setProgress] = useState({ current: 0, total: 0, message: '' });
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [deleteConfirming, setDeleteConfirming] = useState(false);
  const [dbDeleteConfirming, setDbDeleteConfirming] = useState(false);
  const [isApiReady, setIsApiReady] = useState(false);

  // Hidden file input refs
  const fileInputRef = useRef<HTMLInputElement>(null);
  const importDbInputRef = useRef<HTMLInputElement>(null);

  // --- Persistence & API Initialization ---
  useEffect(() => {
    // Load on mount
    const savedVisits = localStorage.getItem('odocalc_visits');
    const savedSettings = localStorage.getItem('odocalc_settings');
    const savedStart = localStorage.getItem('odocalc_start');
    const savedReturn = localStorage.getItem('odocalc_return');

    if (savedVisits) {
      try {
        setVisits(JSON.parse(savedVisits));
      } catch (e) { console.error("Failed to load visits", e); }
    }

    if (savedSettings) {
      try {
        const loaded = JSON.parse(savedSettings);
        if (!loaded.departureTime) loaded.departureTime = "08:00:00";
        if (!loaded.cacheExpirationDays) loaded.cacheExpirationDays = 30;
        if (!loaded.language) loaded.language = 'cs';

        if (!loaded.googleApiKey && DEFAULT_DEV_API_KEY) {
            loaded.googleApiKey = DEFAULT_DEV_API_KEY;
        }

        setSettings(loaded);
        setCacheExpirationDays(loaded.cacheExpirationDays);

        if (loaded.googleApiKey) {
            setRuntimeApiKey(loaded.googleApiKey);
            loadGoogleMapsScript(loaded.googleApiKey)
                .then(() => setIsApiReady(true))
                .catch(e => {
                    console.error("API Load Error:", e);
                    setIsApiReady(false);
                });
        }
      } catch (e) { console.error("Failed to load settings", e); }
    } else {
        if (DEFAULT_DEV_API_KEY) {
            setRuntimeApiKey(DEFAULT_DEV_API_KEY);
            loadGoogleMapsScript(DEFAULT_DEV_API_KEY)
                .then(() => setIsApiReady(true))
                .catch(e => { console.error(e); setIsApiReady(false); });
        } else {
            setRuntimeApiKey("");
            setIsApiReady(false);
        }
    }

    if (savedStart) {
        try { setStartTrip(JSON.parse(savedStart)); } catch (e) { console.error("Failed to load start trip", e); }
    }

    if (savedReturn) {
        try { setReturnTrip(JSON.parse(savedReturn)); } catch (e) { console.error("Failed to load return trip", e); }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('odocalc_visits', JSON.stringify(visits));
    localStorage.setItem('odocalc_settings', JSON.stringify(settings));
    if (startTrip) localStorage.setItem('odocalc_start', JSON.stringify(startTrip));
    else localStorage.removeItem('odocalc_start');
    if (returnTrip) localStorage.setItem('odocalc_return', JSON.stringify(returnTrip));
    else localStorage.removeItem('odocalc_return');

    if (settings.isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [visits, settings, startTrip, returnTrip]);

  useEffect(() => {
    setDeleteConfirming(false);
  }, [selectedIds]);

  const clearCalculation = (currentList: Visit[] = visits) => {
    const cleared = currentList.map(v => {
        const { segmentDistance, exactDistanceKm, segmentDuration, totalOdometer, arrivalTime, ...rest } = v;
        return rest as Visit;
    });
    setStartTrip(null);
    setReturnTrip(null);
    setCalcStatus(CalculationStatus.IDLE);
    if (isMapOpen) setIsMapOpen(false); 
    return cleared;
  };

  const handleExportDB = () => {
      try {
          const getParsed = (key: string) => {
              const val = localStorage.getItem(key);
              return val ? JSON.parse(val) : null;
          };
          const exportData = {
              visits: getParsed('odocalc_visits'),
              settings: getParsed('odocalc_settings'),
              start: getParsed('odocalc_start'),
              return: getParsed('odocalc_return'),
              lmod: getParsed('odocalc_lmod'),
              timestamp: new Date().toISOString()
          };
          const blob = new Blob([JSON.stringify(exportData, null, 2)], { type: 'application/json' });
          const url = URL.createObjectURL(blob);
          const link = document.createElement('a');
          link.href = url;
          link.download = `odocalc-backup-${new Date().toISOString().slice(0,10)}.json`;
          document.body.appendChild(link);
          link.click();
          document.body.removeChild(link);
          URL.revokeObjectURL(url);
      } catch (err: any) {
          alert("Export failed: " + err.message);
      }
  };

  const handleImportDB = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (event) => {
          try {
              const text = event.target?.result as string;
              const data = JSON.parse(text);
              if (!data.visits && !data.settings) throw new Error("Invalid backup file format");
              if (data.lmod) localStorage.setItem('odocalc_lmod', JSON.stringify(data.lmod));
              if (data.settings) setSettings(data.settings);
              if (data.visits) {
                  setVisits(data.visits);
                  setStartTrip(data.start || null);
                  setReturnTrip(data.return || null);
              }
              if (data.settings?.googleApiKey) {
                  setRuntimeApiKey(data.settings.googleApiKey);
                  loadGoogleMapsScript(data.settings.googleApiKey)
                    .then(() => setIsApiReady(true))
                    .catch(() => setIsApiReady(false));
              }
              alert(t.msgImportSuccess);
          } catch (err: any) {
              alert(t.msgImportFail + ": " + err.message);
          }
      };
      reader.readAsText(file);
      if (importDbInputRef.current) importDbInputRef.current.value = '';
  };

  const handleClearDB = () => {
      if (dbDeleteConfirming) {
          localStorage.removeItem('odocalc_lmod');
          setVisits([]);
          setStartTrip(null);
          setReturnTrip(null);
          setSettings({
            startAddress: "Dlouhá 1113, 530 06 Pardubice, Česko",
            currentOdometer: 0,
            departureTime: "08:00:00",
            isStrictMode: false,
            isStartValid: false,
            isDarkMode: true,
            googleApiKey: DEFAULT_DEV_API_KEY,
            cacheExpirationDays: 30,
            language: settings.language // Keep language preference
          });

          if (DEFAULT_DEV_API_KEY) {
            setRuntimeApiKey(DEFAULT_DEV_API_KEY);
            setIsApiReady(true); 
          } else {
            setRuntimeApiKey("");
            setIsApiReady(false);
          }
          setCacheExpirationDays(30); 
          setDbDeleteConfirming(false);
          alert(t.msgDbCleared);
      } else {
          setDbDeleteConfirming(true);
          setTimeout(() => setDbDeleteConfirming(false), 4000);
      }
  };

  const reindexVisits = (list: Visit[]) => {
    let orderCounter = 1;
    return list.map((v) => {
        if (v.isSkipped) return { ...v, order: 0 };
        return { ...v, order: orderCounter++ };
    });
  };

  const handleReorder = (newVisits: Visit[]) => {
    const cleared = clearCalculation(newVisits);
    setVisits(reindexVisits(cleared));
  };

  const handleToggleSkip = (id: string) => {
      const updated = visits.map(v => v.id === id ? { ...v, isSkipped: !v.isSkipped } : v);
      const cleared = clearCalculation(updated);
      setVisits(reindexVisits(cleared));
  };

  const handleAdd = () => {
    setEditingVisit(null);
    setIsModalOpen(true);
  };

  const handleEdit = (visit: Visit) => {
    setEditingVisit(visit);
    setIsModalOpen(true);
  };

  const saveVisit = (data: Omit<Visit, 'id'>) => {
    let newList;
    if (editingVisit) {
      newList = visits.map(v => v.id === editingVisit.id ? { ...v, ...data } : v);
    } else {
      const newVisit = { ...data, id: uuid(), order: 0, isSkipped: false };
      newList = [...visits, newVisit];
    }
    const cleared = clearCalculation(newList);
    setVisits(reindexVisits(cleared));
    setIsModalOpen(false);
  };

  const saveSettings = (newSettings: AppSettings) => {
      if (newSettings.startAddress !== settings.startAddress || newSettings.currentOdometer !== settings.currentOdometer || newSettings.departureTime !== settings.departureTime) {
          const cleared = clearCalculation(visits);
          setVisits(cleared);
      }

      if (newSettings.googleApiKey !== settings.googleApiKey) {
          if (newSettings.googleApiKey) {
              setRuntimeApiKey(newSettings.googleApiKey);
              loadGoogleMapsScript(newSettings.googleApiKey)
                .then(() => setIsApiReady(true))
                .catch(e => {
                    console.error(e);
                    setIsApiReady(false);
                    alert("Failed to load Maps API with this key.");
                });
          } else {
              setRuntimeApiKey("");
              setIsApiReady(false);
          }
      }

      if (newSettings.cacheExpirationDays && newSettings.cacheExpirationDays !== settings.cacheExpirationDays) {
          setCacheExpirationDays(newSettings.cacheExpirationDays);
      }
      setSettings(newSettings);
  };

  const handleDeleteClick = () => {
    if (deleteConfirming) {
        const remainingVisits = visits.filter(v => !selectedIds.has(v.id));
        const cleared = clearCalculation(remainingVisits);
        setVisits(reindexVisits(cleared));
        setSelectedIds(new Set());
        setDeleteConfirming(false);
    } else {
        setDeleteConfirming(true);
        setTimeout(() => setDeleteConfirming(false), 4000);
    }
  };

  const handleDeleteRow = (id: string) => {
      const remaining = visits.filter(v => v.id !== id);
      const cleared = clearCalculation(remaining);
      setVisits(reindexVisits(cleared));
      if (selectedIds.has(id)) {
          const newSelected = new Set(selectedIds);
          newSelected.delete(id);
          setSelectedIds(newSelected);
      }
  };

  const handleExcelUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      const parsed = await parseVisitsExcel(file);
      let newVisits = parsed.map(v => ({ ...v, id: uuid(), isSkipped: false }));

      const validatedVisits = await Promise.all(newVisits.map(async (v) => {
          const check = await checkAddress(v.address);
          return { ...v, address: v.address, isAddressValid: check.isValid };
      }));

      const combined = [...visits, ...validatedVisits];
      const sorted = combined.sort((a, b) => a.order - b.order);
      const cleared = clearCalculation(sorted);

      setVisits(reindexVisits(cleared));
      alert(`${t.msgImportSuccess} (${validatedVisits.length})`);
    } catch (err: any) {
      alert(`${t.msgImportFail}: ${err.message}`);
    } finally {
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const handleValidateAll = async () => {
      if (!isApiReady) return alert(t.msgApiMissing);
      if (visits.length === 0) return alert(t.msgNoVisits);

      setCalcStatus(CalculationStatus.VALIDATING);
      setErrorMsg(null);
      const total = visits.length;
      const newVisits = [...visits];

      try {
          for (let i = 0; i < newVisits.length; i++) {
              const v = newVisits[i];
              setProgress({ current: i + 1, total, message: `${t.msgValidating} ${v.surname}...` });
              const res = await checkAddress(v.address);
              newVisits[i] = { ...v, isAddressValid: res.isValid };
              await sleep(20); 
          }
          setVisits(newVisits);
          alert(`${t.msgValidationComplete} (${total})`);
      } catch (err: any) {
          console.error(err);
          setErrorMsg(err.message);
      } finally {
          setCalcStatus(CalculationStatus.IDLE);
      }
  };

  const runCalculation = async (visitsOverride?: Visit[], commitOdometer: boolean = true) => {
    if (!isApiReady) return alert(t.msgApiMissing);
    const sourceVisits = visitsOverride || visits;
    const activeVisits = sourceVisits.filter(v => !v.isSkipped);

    if (activeVisits.length === 0) return alert(t.msgNoActive);
    if (!settings.startAddress) return alert(t.msgStartReq);

    setCalcStatus(CalculationStatus.VALIDATING);
    setErrorMsg(null);
    setStartTrip(null);
    setReturnTrip(null);

    const processingAllVisits = [...sourceVisits];
    let currentOdo = settings.currentOdometer;
    let currentLoc = settings.startAddress;
    let returnDest = settings.startAddress; 
    let currentClock = settings.departureTime || "08:00:00";

    const initialStartData: StartTrip = { address: settings.startAddress, odometer: settings.currentOdometer };
    const totalSteps = activeVisits.length + (settings.isStrictMode ? activeVisits.length + 1 : 1); 
    let stepCount = 0;
    const updateProgress = (msg: string) => {
      stepCount++;
      setProgress({ current: stepCount, total: totalSteps, message: msg });
    };

    try {
      if (settings.isStrictMode) {
        if (!settings.isStartValid) {
            updateProgress(`${t.msgValidating} START...`);
            const validStart = await validateAddressStrict(settings.startAddress);
            currentLoc = validStart;
            returnDest = validStart;
        }
        for (let i = 0; i < processingAllVisits.length; i++) {
          if (processingAllVisits[i].isSkipped) continue;
          const v = processingAllVisits[i];
          if (!v.isAddressValid) {
             updateProgress(`${t.msgValidating} ${v.surname}...`);
             await validateAddressStrict(v.address); 
             processingAllVisits[i].isAddressValid = true; 
          }
        }
      }

      setStartTrip(initialStartData);
      setCalcStatus(CalculationStatus.ROUTING);

      for (let i = 0; i < processingAllVisits.length; i++) {
        if (processingAllVisits[i].isSkipped) continue;
        const visit = processingAllVisits[i];
        updateProgress(`${t.msgRouting} ${visit.surname}...`);

        const routeDest = visit.address;
        const { distanceKm, durationSeconds } = await getRouteData(currentLoc, routeDest);
        const roundedDist = commercialRound(distanceKm);
        currentOdo += roundedDist;

        const arrivalTime = addSecondsToTime(currentClock, durationSeconds);
        const visitDurationSeconds = (visit.visitDuration || 0) * 60;
        currentClock = addSecondsToTime(arrivalTime, visitDurationSeconds);

        processingAllVisits[i].segmentDistance = roundedDist;
        processingAllVisits[i].exactDistanceKm = distanceKm; 
        processingAllVisits[i].segmentDuration = durationSeconds;
        processingAllVisits[i].arrivalTime = arrivalTime;

        if (commitOdometer) processingAllVisits[i].totalOdometer = currentOdo;
        else processingAllVisits[i].totalOdometer = undefined;

        setVisits([...processingAllVisits]); 
        currentLoc = routeDest;
        await sleep(50);
      }

      updateProgress(t.msgCalcReturn);
      const { distanceKm: returnDist, durationSeconds: returnDur } = await getRouteData(currentLoc, returnDest);
      const roundedReturn = commercialRound(returnDist);
      currentOdo += roundedReturn;
      const returnArrivalTime = addSecondsToTime(currentClock, returnDur);

      setReturnTrip({
        address: settings.startAddress, 
        segmentDistance: roundedReturn,
        exactDistanceKm: returnDist,
        segmentDuration: returnDur,
        arrivalTime: returnArrivalTime,
        totalOdometer: commitOdometer ? currentOdo : undefined
      });

      setCalcStatus(CalculationStatus.COMPLETE);
      if (commitOdometer) setSettings(prev => ({ ...prev, currentOdometer: currentOdo }));

    } catch (err: any) {
      console.error(err);
      setErrorMsg(err.message || "An unknown error occurred during calculation.");
      setCalcStatus(CalculationStatus.ERROR);
      setStartTrip(null);
    }
  };

  const handleOptimizeRoute = async () => {
      if (!isApiReady) return alert(t.msgApiMissing);
      const activeVisits = visits.filter(v => !v.isSkipped);
      if (activeVisits.length < 2) return alert(t.msgNoActive);
      if (!settings.startAddress) return alert(t.msgStartReq);

      setCalcStatus(CalculationStatus.ROUTING);
      setErrorMsg(null);
      setProgress({ current: 0, total: 100, message: 'Checking cached distances...' });

      try {
          const allAddresses = [settings.startAddress, ...activeVisits.map(v => v.address)];
          await ensureMatrixData(allAddresses, (msg) => { setProgress(prev => ({ ...prev, message: msg })); });
          setProgress({ current: 90, total: 100, message: 'Solving TSP...' });
          await sleep(100);

          const optimizedActive = solveTSP(settings.startAddress, activeVisits);
          const skippedVisits = visits.filter(v => v.isSkipped);
          const newOrder = [...optimizedActive, ...skippedVisits];

          const reindexed = reindexVisits(clearCalculation(newOrder));
          setVisits(reindexed);
          await runCalculation(reindexed, false);
      } catch (err: any) {
          console.error(err);
          setErrorMsg(`${t.msgOptFail}: ${err.message}`);
          setCalcStatus(CalculationStatus.ERROR);
      }
  };

  const getProgressWidth = () => {
    if (progress.total === 0) return 0;
    return Math.min(100, Math.floor((progress.current / progress.total) * 100));
  };

  const canVisualize = !!startTrip && visits.some(v => !v.isSkipped && v.segmentDistance !== undefined);
  const shouldDisableActions = settings.isStrictMode && visits.some(v => !v.isSkipped && v.isAddressValid === false);

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900 p-4 md:p-8 transition-colors duration-200">
      <div className="max-w-screen-2xl mx-auto space-y-6">
        <header className="flex flex-col md:flex-row md:items-center justify-between bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 transition-colors">
          <div className="mb-4 md:mb-0">
            <h1 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
              <span className="text-google-blue">{t.appTitle}</span>
            </h1>
            <p className="text-gray-500 dark:text-gray-400 text-xs flex items-center gap-1">
                {t.subTitle}
                {isApiReady ? (
                    <span className="text-green-500 flex items-center" title="API Ready"><svg className="w-3 h-3" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M5 9V7a5 5 0 0110 0v2a2 2 0 012 2v5a2 2 0 01-2 2H5a2 2 0 01-2-2v-5a2 2 0 012-2zm8-2v2H7V7a3 3 0 016 0z" clipRule="evenodd" /></svg></span>
                ) : (
