const SortableRow: React.FC<SortableRowProps> = ({ visit, isSelected, onToggleSelect, onEdit, onToggleSkip, onDelete, isFiltering }) => {
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging
  } = useSortable({ id: visit.id, disabled: isFiltering });

  const [deleteConfirming, setDeleteConfirming] = React.useState(false);

  const style = {
    transform: CSS.Translate.toString(transform),
    transition,
    zIndex: isDragging ? 50 : 'auto',
    position: isDragging ? 'relative' as const : 'static' as const,
  };

  const hasCalc = visit.segmentDistance !== undefined && !visit.isSkipped;
  const isSkipped = visit.isSkipped;
  const showOdometer = hasCalc && visit.totalOdometer !== undefined;

  return (
    <tr 
      ref={setNodeRef} 
      style={style} 
      onDoubleClick={(e) => {
        if (e.target instanceof HTMLElement) {
             const tagName = e.target.tagName;
             if (tagName !== 'INPUT' && tagName !== 'BUTTON' && tagName !== 'SVG' && tagName !== 'PATH') {
                 onToggleSkip(visit.id);
             }
        }
      }}
      className={`transition-colors cursor-pointer 
        ${isDragging ? 'bg-blue-50 dark:bg-blue-900/30 shadow-lg' : 'hover:bg-gray-50 dark:hover:bg-gray-700 bg-white dark:bg-gray-800'}
        ${isSkipped ? 'opacity-50 grayscale' : 'text-gray-900 dark:text-gray-100'}
      `}
