                                    </button>
                                )}
                                <button 
                                    onClick={() => handleDelete(route.id)}
                                    className={`p-2 rounded-full transition-all ${isDeleting ? 'bg-red-600 text-white shadow-md scale-110' : 'text-red-500 hover:bg-red-50 dark:hover:bg-red-900/30'}`}
                                    title={isDeleting ? t.confirm : t.delete}
                                >
