    if (savedStart) { try { setStartTrip(JSON.parse(savedStart)); } catch (e) { console.error("Failed to load start trip", e); } }
    if (savedReturn) { try { setReturnTrip(JSON.parse(savedReturn)); } catch (e) { console.error("Failed to load return trip", e); } }
  }, []);

